INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12501, 1, '🎧 노이즈 캔슬링 무선 헤드셋', '', '🚀 주변 소음 완벽 차단! 음악에만 몰입하세요\n💎 프리미엄 사운드 & 40시간 재생\n⚡ 지금 사면 전용 케이스 증정\n▶ 제품 보기', '', 1090000.00, 5450),
(12502, 1, '💻 초경량 비즈니스 노트북 특가', '', '✨ 990g의 가벼움으로 어디서나 자유롭게\n🎯 최신 프로세서 탑재로 압도적 성능\n🔥 대학생/직장인 한정 추가 할인\n🚀 지금 클릭', '', 480000.00, 2400),
(12503, 1, '⌚ 스마트워치 8세대 신규 런칭', '', '📈 체성분 분석부터 수면 케어까지\n🎨 내 맘대로 바꾸는 스트랩 기획전\n📌 선착순 100명 보호필름 무료\n▶ 구매하기', '', 1770000.00, 8850),
(12504, 1, '🖱️ 무소음 무선 마우스 1+1', '', '🤫 카페에서도 도서관에서도 조용하게\n✨ 손목이 편한 인체공학적 디자인\n⚡ 2개 구매 시 30% 파격 할인\n▶ 득템하기', '', 1160000.00, 5800),
(12505, 1, '🔋 초고속 충전 보조배터리 20000mAh', '', '⚡ 스마트폰부터 노트북까지 한 번에\n💎 잔량 확인 LED 디스플레이 탑재\n📌 기내 반입 가능 안전 인증\n🚀 바로 주문', '', 550000.00, 2750),
(12506, 1, '📷 브이로그용 미러리스 카메라', '', '🎬 찍기만 해도 화보가 되는 색감\n🎯 초보자도 쉬운 풀 오토 모드\n🎁 지금 구매 시 메모리카드 증정\n▶ 구경가기', '', 1840000.00, 9200),
(12507, 1, '📺 4K UHD 65인치 스마트 TV', '', '🏟️ 거실을 영화관으로 만드는 화질\n✨ 넷플릭스, 유튜브 원클릭 실행\n⚡ 주말 한정 무료 배송 & 설치\n🚀 지금 확인', '', 1230000.00, 6150),
(12508, 1, '⌨️ 기계식 키보드 타건감 끝판왕', '', '🎮 게임의 재미를 더하는 화려한 RGB\n💎 오타 없는 정확한 입력 시스템\n📌 한정판 키캡 증정 이벤트\n▶ 상세 보기', '', 620000.00, 3100),
(12509, 1, '📱 최신 스마트폰 자급제 파격가', '', '✨ 약정 없이 자유로운 통신사 선택\n🎯 고성능 카메라로 인생샷 완성\n💸 카드사별 무이자 혜택 제공\n🚀 바로 구매', '', 1910000.00, 9550),
(12510, 1, '🔈 블루투스 스피커 감성 인테리어', '', '🎵 캠핑장에서도 거실에서도 웅장하게\n🎨 디자인까지 완벽한 인테리어 소품\n⚡ 오늘 주문 시 당일 발송\n▶ 더 보기', '', 1300000.00, 6500),
(12511, 1, '🎮 차세대 콘솔 게임기 패키지', '', '🔥 집에서 즐기는 리얼한 그래픽\n🎯 인기 타이틀 2종 무료 포함\n📌 선착순 한정 수량 입고\n🚀 지금 클릭', '', 690000.00, 3450),
(12512, 1, '🖥️ 32인치 커브드 게이밍 모니터', '', '✨ 144Hz 주사율로 끊김 없는 플레이\n💎 눈이 편안한 플리커 프리 기술\n⚡ 런칭 기념 특가 세일 중\n▶ 확인하기', '', 1980000.00, 9900),
(12513, 1, '🖨️ 가정용 무한잉크 복합기', '', '📑 인쇄, 복사, 스캔을 하나로\n💸 유지비 걱정 없는 경제적인 모델\n📌 정품 잉크 추가 증정 이벤트\n🚀 지금 구매', '', 1370000.00, 6850),
(12514, 1, '🧥 스마트 의류 관리기 렌탈', '', '✨ 매일 새 옷처럼 뽀송하게 살균\n🎯 미세먼지부터 냄새까지 싹!\n📞 상담 신청 시 첫 달 무료\n▶ 상담 받기', '', 760000.00, 3800),
(12515, 1, '🌬️ 공기청정기 필터 1년치 포함', '', '💎 초미세먼지 99.9% 완벽 제거\n✨ 스마트폰 앱으로 원격 제어 가능\n💸 렌탈보다 싼 일시불 특가\n🚀 지금 확인', '', 150000.00, 750),
(12516, 1, '🧹 로봇청소기 물걸레 겸용 모델', '', '🎯 알아서 척척! 스마트 매핑 기술\n✨ 반려동물 털 고민 해결사\n📌 오늘 구매 시 교체용 소모품 증정\n▶ 더 보기', '', 1440000.00, 7200),
(12517, 1, '🧊 저소음 미니 냉장고 1인가구 필수', '', '🎨 감각적인 디자인으로 공간 활용\n💎 화장품 냉장고로도 인기 만점\n⚡ 한정 수량 할인 이벤트\n🚀 구매하기', '', 830000.00, 4150),
(12518, 1, '💧 초음파 가습기 세척이 쉬운 모델', '', '✨ 환절기 비염 예방! 적정 습도 유지\n🎯 넉넉한 물탱크로 밤새 촉촉하게\n📌 구매평 1,000개 돌파 감사제\n▶ 확인하기', '', 220000.00, 1100),
(12519, 1, '🍳 에어프라이어 5L 대용량 특가', '', '🍗 겉바속촉 요리의 완성을 집에서\n💎 올 스테인리스로 안전한 사용\n🎁 전용 레시피북 무료 증정\n🚀 지금 주문', '', 1510000.00, 7550),
(12520, 1, '☕ 캡슐 커피머신 홈카페 패키지', '', '☕ 버튼 하나로 즐기는 프리미엄 커피\n✨ 캡슐 30구 + 전용 거치대 포함\n⚡ 신규 고객 50% 할인 혜택\n▶ 구경하기', '', 900000.00, 4500),
(12521, 1, '🏋️ 스마트 체중계 인바디 측정', '', '📈 근육량부터 체지방까지 한 눈에\n✨ 앱 연동으로 체계적인 관리\n📌 가족 모두 사용 가능한 멀티 유저\n🚀 지금 구매', '', 290000.00, 1450),
(12522, 1, '💇 전문가용 드라이기 초고속 건조', '', '✨ 손상 없는 음이온 케어 시스템\n🎯 강력한 바람으로 아침 시간 단축\n⚡ 특가 판매 마감 임박\n▶ 제품 보기', '', 1580000.00, 7900),
(12523, 1, '💆 저주파 마사지기 목 어깨 전용', '', '🔋 언제 어디서나 시원하게 힐링\n💎 작지만 강력한 마사지 효과\n📌 부모님 효도 선물 1위\n🚀 지금 클릭', '', 970000.00, 4850),
(12524, 1, '📽️ 빔프로젝터 나만의 영화관', '', '🎬 최대 150인치 대화면의 감동\n✨ 캠핑장 필수 템! 무선 연결 지원\n🎁 스크린 무료 증정 이벤트\n▶ 확인하기', '', 360000.00, 1800),
(12525, 1, '👜 노트북 파우치 감성 디자인', '', '🎨 내 기기를 안전하게 보호하세요\n💎 생활 방수 & 충격 완화 내장재\n⚡ 13/15/17인치 전 사이즈 입고\n🚀 바로 주문', '', 1650000.00, 8250),
(12526, 1, '📻 레트로 블루투스 라디오', '', '🎵 아날로그 감성에 최신 기능 장착\n✨ 인테리어 무드등 기능 포함\n📌 선물용 기프트 박스 제공\n▶ 구경하기', '', 1040000.00, 5200),
(12527, 1, '📏 전자 줄자 거리 측정기', '', '🛠️ 버튼 하나로 정확한 수치 측정\n✨ 이사, 인테리어 준비 필수 아이템\n⚡ 전문가용 모델 특가 판매\n🚀 지금 확인', '', 430000.00, 2150),
(12528, 1, '🏮 캠핑용 LED 랜턴 감성 충전', '', '✨ 3단계 밝기 조절 & 보조배터리 기능\n💎 비와도 안심! 완전 방수 설계\n📌 캠핑족 강력 추천 템\n▶ 구매하기', '', 1720000.00, 8600),
(12529, 1, '🎙️ 1인 방송용 마이크 패키지', '', '🎧 잡음 없이 깨끗한 목소리 전달\n✨ 유튜브 입문자를 위한 풀세트\n⚡ 거치대 + 팝필터 증정 중\n🚀 지금 클릭', '', 1110000.00, 5550),
(12530, 1, '🔌 멀티탭 6구 개별 스위치', '', '⚡ 과부하 차단으로 화재 예방\n💎 책상 위 깔끔한 선 정리의 시작\n📌 1+1 묶음 배송 할인\n▶ 더 보기', '', 500000.00, 2500),
(12531, 1, '🚲 전기 자전거 출퇴근 혁명', '', '⚡ 오르막길도 평지처럼 가볍게\n💎 한 번 충전으로 50km 주행\n📌 시승 신청 이벤트 진행 중\n🚀 지금 확인', '', 1790000.00, 8950),
(12532, 1, '🛴 전동 킥보드 경량 폴딩 모델', '', '✨ 대중교통 연계에 딱! 간편 수납\n🎯 고성능 브레이크로 안전 주행\n⚡ 헬멧 증정 기획전 실시\n▶ 바로 구매', '', 1180000.00, 5900),
(12533, 1, '🌡️ 비접촉식 체온계 정확도 1위', '', '✨ 빠르고 안전한 온도 측정\n💎 영유아 가정 필수 상비품\n📌 공식 정품 할인 판매\n🚀 지금 주문', '', 570000.00, 2850),
(12534, 1, '🧊 탁상용 미니 선풍기 저소음', '', '🌬️ 책상 위 나만의 시원한 바람\n✨ USB 충전 방식으로 편리하게\n⚡ 여름 미리 준비 특가 진행\n▶ 더 보기', '', 1860000.00, 9300),
(12535, 1, '🍞 2구 토스터기 바삭한 아침', '', '✨ 굽기 조절 7단계로 취향 존중\n💎 먼지 방지 덮개 포함 위생적\n📌 신혼부부 선물 추천\n🚀 지금 클릭', '', 1250000.00, 6250),
(12536, 1, '💧 휴대용 구강세정기 치아 관리', '', '🦷 칫솔이 닿지 않는 곳까지 시원하게\n✨ 교정 중이라면 필수 아이템\n⚡ 지금 사면 노즐 2개 추가\n▶ 확인하기', '', 640000.00, 3200),
(12537, 1, '🧔 전기 면도기 건습식 겸용', '', '✨ 밀착 면도로 자극 없는 깔끔함\n🎯 자동 세척 스테이션 패키지\n📌 아빠/남편 선물 강력 추천\n🚀 바로 구매', '', 1930000.00, 9650),
(12538, 1, '🎵 골전도 이어폰 귀가 편한 설계', '', '🎧 야외 활동 시 주변 소리 감지 가능\n✨ 장시간 착용해도 통증 제로\n⚡ 운동 마니아 필수 아이템\n▶ 구경하기', '', 1320000.00, 6600),
(12539, 1, '💼 태블릿 PC 전용 키보드 케이스', '', '✨ 내 태블릿을 노트북처럼 사용\n💎 강력한 자력 홀더 & 백라이트\n📌 전 기종 호환 모델 입고\n🚀 지금 확인', '', 710000.00, 3550),
(12540, 1, '💾 외장 SSD 1TB 초고속 전송', '', '🚀 HDD보다 10배 빠른 데이터 백업\n✨ 한 손에 쏙 들어오는 미니 사이즈\n⚡ 중요한 자료 안전하게 보관\n▶ 구매하기', '', 100000.00, 500),
(12541, 1, '👔 보풀 제거기 강력한 모터', '', '✨ 헌 옷을 새 옷처럼 깔끔하게\n💎 옷감 손상 방지 특수 가드\n📌 선착순 리필 날 증정\n🚀 지금 주문', '', 1390000.00, 6950),
(12542, 1, '🥣 초고속 블렌더 진공 믹서기', '', '✨ 영양소 파괴 없는 리얼 주스\n🎯 얼음까지 곱게 갈리는 파워\n⚡ 홈쇼핑 히트 상품 특가전\n▶ 더 보기', '', 780000.00, 3900),
(12543, 1, '🧴 초음파 세척기 안경 시계 관리', '', '💎 미세 틈새 오염까지 완벽 제거\n✨ 버튼 하나로 전문가급 세척\n📌 화장품 브러쉬도 세척 가능\n🚀 바로 클릭', '', 170000.00, 850),
(12544, 1, '🎸 전자 기타 입문용 풀세트', '', '🎵 취미 생활의 시작! 앰프 포함\n✨ 튜닝기부터 케이스까지 다 드림\n⚡ 기초 강좌 수강권 무료 증정\n▶ 확인하기', '', 1460000.00, 7300),
(12545, 1, '🎹 디지털 피아노 88건반 특가', '', '✨ 층간 소음 걱정 없는 헤드폰 모드\n🎯 실제 피아노 같은 묵직한 터치감\n🎁 전용 의자 포함 패키지\n🚀 지금 구매', '', 850000.00, 4250),
(12546, 1, '🔦 강력 LED 손전등 캠핑 낚시용', '', '✨ 500m 앞도 환하게 비추는 파워\n💎 줌 조절 기능 & 보조배터리 겸용\n📌 재난 대비 필수 아이템\n▶ 구경하기', '', 240000.00, 1200),
(12547, 1, '🕶️ 스마트 오디오 안경 선글라스', '', '🎧 음악 감상과 자외선 차단을 동시에\n✨ 통화 기능 탑재된 미래형 안경\n⚡ 신규 가입 시 20% 할인\n🚀 지금 확인', '', 1530000.00, 7650),
(12548, 1, '📱 스마트폰 삼각대 셀카봉 겸용', '', '🎬 여행 인생샷을 위한 필수 템\n✨ 블루투스 리모컨 포함 멀티 기능\n📌 가볍고 튼튼한 알루미늄 소재\n▶ 구매하기', '', 920000.00, 4600),
(12549, 1, '🧊 얼음 정수기 렌탈 프로모션', '', '💧 깨끗한 물과 투명한 얼음을 한 번에\n✨ 스테인리스 관으로 더 위생적\n📞 제휴 카드 이용 시 월 0원\n🚀 상담 신청', '', 310000.00, 1550),
(12550, 1, '🦾 전신 안마의자 프리미엄 기획전', '', '💆 하루의 피로를 녹이는 무중력 모드\n💎 AI 체형 맞춤 마사지 시스템\n⚡ 전시 상품 파격 세일 진행\n▶ 혜택 보기', '', 1600000.00, 8000);
