INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12551, 1, '🎧 커스텀 사운드 유선 이어폰', '', '🎵 전문가용 튜닝으로 즐기는 고음질\n💎 꼬임 방지 트위스트 케이블 채택\n⚡ 지금 구매 시 파우치 증정\n▶ 제품 보기', '', 990000.00, 4950),
(12552, 1, '💻 노트북 거치대 알루미늄 소재', '', '✨ 6단계 높이 조절로 거북목 예방\n🎯 접이식 디자인으로 휴대성 극대화\n🔥 오피스 필수 아이템 특가 세일\n🚀 지금 클릭', '', 380000.00, 1900),
(12553, 1, '⌚ 스마트워치 메탈 스트랩 기획전', '', '🎨 평범한 워치를 명품 시계처럼\n💎 부식 없는 프리미엄 스테인리스\n📌 2개 이상 구매 시 교체 도구 증정\n▶ 구경하기', '', 1670000.00, 8350),
(12554, 1, '🖱️ 버티컬 마우스 손목 보호형', '', '🤫 장시간 작업에도 손목 통증 제로\n✨ 인체공학적 57도 수직 디자인\n⚡ 신규 런칭 기념 20% 할인\n▶ 확인하기', '', 1060000.00, 5300),
(12555, 1, '🔋 자석형 맥세이프 보조배터리', '', '⚡ 붙이기만 하면 무선 충전 시작\n💎 초슬림 사이즈로 뛰어난 휴대성\n📌 아이폰 전 기종 완벽 호환\n🚀 바로 주문', '', 450000.00, 2250),
(12556, 1, '📷 액션캠 여행 브이로그 패키지', '', '🎬 흔들림 없는 4K 고화질 영상\n🎯 수중 촬영 가능한 방수 케이스 포함\n🎁 셀카봉 & 배터리 추가 증정\n▶ 상세 보기', '', 1740000.00, 8700),
(12557, 1, '📺 거실용 사운드바 홈시어터 완성', '', '🏟️ 영화관 같은 압도적 베이스 사운드\n✨ 블루투스 연결로 간편한 사용\n⚡ TV 구매 고객 추가 할인 혜택\n🚀 지금 확인', '', 1130000.00, 5650),
(12558, 1, '⌨️ 무선 기계식 키보드 텐키리스', '', '🎮 책상을 더 넓게 쓰는 컴팩트 사이즈\n💎 핫스왑 지원으로 스위치 교체 가능\n📌 한정 수량 입고 완료\n▶ 구매하기', '', 520000.00, 2600),
(12559, 1, '📱 스마트폰 방수팩 물놀이 필수템', '', '✨ 수심 10m까지 완벽 방수 보장\n🎯 케이스 낀 채로 터치 가능\n💸 1+1 묶음 세트 한정 판매\n🚀 바로 구매', '', 1810000.00, 9050),
(12560, 1, '🔈 미니 블루투스 스피커 휴대용', '', '🎵 한 손에 쏙 들어오는 강력한 소리\n🎨 파스텔 톤의 감성적인 디자인\n⚡ 캠핑/피크닉 강력 추천템\n▶ 더 보기', '', 1200000.00, 6000),
(12561, 1, '🎮 게이밍 헤드셋 가상 7.1채널', '', '🔥 적의 발소리까지 들리는 공간감\n🎯 노이즈 캔슬링 마이크 탑재\n📌 PC/콘솔 완벽 호환\n🚀 지금 클릭', '', 590000.00, 2950),
(12562, 1, '🖥️ 모니터 암 싱글/듀얼 기획전', '', '✨ 책상 위를 깔끔하게 정리하세요\n💎 자유로운 각도 조절 & 피벗 지원\n⚡ 설치 가이드 무료 제공\n▶ 확인하기', '', 1880000.00, 9400),
(12563, 1, '🖨️ 휴대용 포토 프린터 즉석 인화', '', '📑 스마트폰 사진을 바로 출력\n💸 잉크가 필요 없는 제로 잉크 방식\n📌 전용 인화지 20매 증정\n🚀 지금 구매', '', 1270000.00, 6350),
(12564, 1, '🧥 신발 관리기 냄새 제거 살균', '', '✨ 축축한 신발을 쾌적하게 건조\n🎯 강력한 UV 살균으로 세균 박멸\n📞 렌탈 상담 시 사은품 증정\n▶ 상담 받기', '', 660000.00, 3300),
(12565, 1, '🌬️ 서큘레이터 저소음 BLDC 모터', '', '💎 에어컨 효율을 높이는 공기 순환\n✨ 12단계 바람 조절 & 리모컨 포함\n💸 얼리버드 역대급 할인율\n🚀 지금 확인', '', 1950000.00, 9750),
(12566, 1, '🧹 침구 청소기 UV 살균 기능', '', '🎯 보이지 않는 진드기까지 흡입\n✨ 고온 스팀으로 99% 살균 효과\n📌 아이 키우는 집 필수 아이템\n▶ 더 보기', '', 1340000.00, 6700),
(12567, 1, '🧊 차량용 미니 냉장고 캠핑 필수', '', '🎨 시가잭 연결로 어디서든 시원하게\n💎 온장고 기능 겸용 사계절 사용\n⚡ 한정 수량 주말 특가\n🚀 구매하기', '', 730000.00, 3650),
(12568, 1, '💧 대용량 가습기 상부 급수형', '', '✨ 물 보충이 간편한 오픈형 구조\n🎯 최대 24시간 연속 가습 가능\n📌 사무실/거실용 강력 추천\n▶ 확인하기', '', 120000.00, 600),
(12569, 1, '🍳 와플 메이커 3in1 교체형 팬', '', '🍗 와플, 샌드위치, 붕어빵까지\n💎 논스틱 코팅으로 눌어붙지 않음\n🎁 전용 집게 증정 이벤트\n🚀 지금 주문', '', 1410000.00, 7050),
(12570, 1, '☕ 전동 커피 그라인더 맷돌 방식', '', '☕ 원두 향을 살리는 정교한 분쇄\n✨ 굵기 조절로 취향껏 즐기세요\n⚡ 홈카페 입문자 필수 아이템\n▶ 구경하기', '', 800000.00, 4000),
(12571, 1, '🏋️ 스마트 줄넘기 카운트 기능', '', '📈 앱 연동으로 소모 칼로리 확인\n✨ 노라인 추 포함으로 실내 가능\n📌 다이어트 시작하는 분 추천\n🚀 지금 구매', '', 190000.00, 950),
(12572, 1, '💇 휴대용 미니 고데기 USB 충전', '', '✨ 가방에 쏙! 언제 어디서나 스타일링\n🎯 앞머리 교정에 최적화된 사이즈\n⚡ 여행용 필수 뷰티 가전\n▶ 제품 보기', '', 1480000.00, 7400),
(12573, 1, '💆 눈 마사지기 온열 힐링 모드', '', '🔋 피로한 눈을 위한 따뜻한 휴식\n💎 공기압 마사지로 시원하게\n📌 직장인/수험생 선물 추천\n🚀 지금 클릭', '', 870000.00, 4350),
(12574, 1, '📽️ 스마트 빔 스크린 일체형 패키지', '', '🎬 넷플릭스 내장으로 연결 없이 감상\n✨ 자동 키스톤으로 화면 왜곡 보정\n🎁 삼각대 포함 풀세트 구성\n▶ 확인하기', '', 260000.00, 1300),
(12575, 1, '👜 아이패드 드로잉 케이스 홀더', '', '🎨 애플펜슬 수납 및 무선 충전 지원\n💎 부드러운 안감으로 스크래치 방지\n⚡ 감각적인 5가지 컬러 출시\n🚀 바로 주문', '', 1550000.00, 7750),
(12576, 1, '📻 감성 LP 턴테이블 블루투스 겸용', '', '🎵 LP의 아날로그 음질을 그대로\n✨ 내장 스피커로 별도 연결 불필요\n📌 입문용 가성비 모델 출시\n▶ 구경하기', '', 940000.00, 4700),
(12577, 1, '📏 디지털 수평계 셀프 인테리어', '', '🛠️ LCD 화면으로 정확한 각도 확인\n✨ 가구 조립, 액자 걸기 필수템\n⚡ 전문가용 모델 특가 판매\n🚀 지금 확인', '', 330000.00, 1650),
(12578, 1, '🏮 태양광 정원등 야외 조명', '', '✨ 전기료 0원! 낮에 충전 밤에 점등\n💎 방수 설계로 비바람에도 안심\n📌 마당/테라스 인테리어 끝판왕\n▶ 구매하기', '', 1620000.00, 8100),
(12579, 1, '🎙️ 스마트폰용 핀 마이크 인터뷰용', '', '🎧 주변 소음 없이 목소리만 선명하게\n✨ 긴 케이블로 자유로운 움직임\n⚡ 브이로그/유튜브 촬영 필수\n🚀 지금 클릭', '', 1010000.00, 5050),
(12580, 1, '🔌 질화갈륨(GaN) 65W 멀티 충전기', '', '⚡ 노트북과 폰을 동시에 초고속 충전\n💎 작지만 강력한 차세대 소재 사용\n📌 3포트 구성으로 선 정리 깔끔\n▶ 더 보기', '', 400000.00, 2000),
(12581, 1, '🚲 자전거용 블랙박스 라이딩 필수', '', '⚡ 전후방 동시 녹화로 사고 대비\n💎 야간 주행 시에도 선명한 화질\n📌 헬멧 장착용 거치대 포함\n🚀 지금 확인', '', 1690000.00, 8450),
(12582, 1, '🛴 전동 보드 원휠 스마트 주행', '', '✨ 미래형 개인 이동수단 체험\n🎯 체중 이동으로 간편한 조작\n⚡ 안전 보호구 세트 사은품\n▶ 바로 구매', '', 1080000.00, 5400),
(12583, 1, '🌡️ 디지털 온습도계 정밀 측정', '', '✨ 쾌적한 실내 환경 관리의 시작\n💎 아이 방, 옷방 적정 수치 알림\n📌 깔끔한 화이트 디자인\n🚀 지금 주문', '', 470000.00, 2350),
(12584, 1, '🧊 목걸이형 휴대용 선풍기 무선', '', '🌬️ 손이 자유로운 넥밴드 디자인\n✨ 머리카락 끼임 방지 설계 적용\n⚡ 야외 활동 시 시원함 유지\n▶ 더 보기', '', 1760000.00, 8800),
(12585, 1, '🍞 오븐 토스터기 대용량 12L', '', '✨ 베이킹부터 스테이크까지 한 번에\n💎 상하 이중 열선으로 골고루 조리\n📌 주방 분위기 살리는 레트로풍\n🚀 지금 클릭', '', 1150000.00, 5750),
(12586, 1, '💧 칫솔 살균기 벽걸이 무선형', '', '🦷 99.9% 살균으로 위생적인 구강 관리\n✨ 면도기 거치 가능 멀티 설계\n⚡ UV-C 램프 탑재 모델\n▶ 확인하기', '', 540000.00, 2700),
(12587, 1, '🧔 콧털 정리기 저소음 방수 모델', '', '✨ 깔끔한 첫인상을 위한 필수 매너\n🎯 피부 자극 없는 회전식 칼날\n📌 휴대용 배터리 방식\n🚀 바로 구매', '', 1830000.00, 9150),
(12588, 1, '🎵 수면용 골전도 헤드셋 편안한 착용', '', '🎧 옆으로 누워도 통증 없는 설계\n✨ 백색 소음 및 수면 유도 앱 연동\n⚡ 불면증 고민 해결사\n▶ 구경하기', '', 1220000.00, 6100),
(12589, 1, '💼 노트북 백팩 USB 충전 포트 내장', '', '✨ 이동 중에도 간편하게 기기 충전\n💎 17인치 대형 노트북 완벽 수납\n📌 도난 방지 포켓 설계 적용\n🚀 지금 확인', '', 610000.00, 3050),
(12590, 1, '💾 마이크로 SD카드 512GB 고성능', '', '🚀 4K 영상 녹화도 끊김 없이 지원\n✨ 닌텐도 스위치/드론 완벽 호환\n⚡ 10년 보증 서비스 제공\n▶ 구매하기', '', 1900000.00, 9500),
(12591, 1, '👔 핸디 스팀 다리미 30초 고속 예열', '', '✨ 바쁜 아침 쓱쓱- 칼주름 완성\n💎 강력 스팀으로 살균 탈취 효과\n📌 물통 탈부착형 위생적 관리\n🚀 지금 주문', '', 1290000.00, 6450),
(12592, 1, '🥣 요거트 메이커 전기 필요 없는 타입', '', '✨ 우유만 넣으면 홈메이드 요거트 완성\n🎯 환경호르몬 걱정 없는 소재\n⚡ 온 가족 영양 간식 만들기\n▶ 더 보기', '', 680000.00, 3400),
(12593, 1, '🧴 전동 브러쉬 욕실 청소 혁명', '', '💎 힘들게 문지르지 마세요! 자동 회전\n✨ 줄눈 때부터 타일 광택까지\n📌 3가지 교체 헤드 포함\n🚀 바로 클릭', '', 1970000.00, 9850),
(12594, 1, '🎸 일렉 기타 이펙터 멀티 프로세서', '', '🎵 수백 가지 사운드를 기기 하나로\n✨ 버스킹, 녹음 필수 장비\n⚡ 전용 어댑터 포함 특가전\n▶ 확인하기', '', 1360000.00, 6800),
(12595, 1, '🎹 61건반 입문용 키보드 화이트', '', '✨ 가볍고 슬림한 디자인의 연습용\n🎯 내장된 100가지 음색과 리듬\n🎁 악보 거치대 무료 증정\n🚀 지금 구매', '', 750000.00, 3750),
(12596, 1, '🔦 헤드 랜턴 낚시/등산용 고휘도', '', '✨ 밤낚시 필수! 두 손이 자유롭게\n💎 센서 모드로 손짓만 해도 점등\n📌 충전식 배터리 내장형\n▶ 구경하기', '', 140000.00, 700),
(12597, 1, '🕶️ 블루라이트 차단 안경 초경량', '', '🎧 장시간 PC 작업 시 눈 피로 감소\n✨ 도수 없는 패션 안경 겸용\n⚡ 안경 닦이 & 케이스 세트\n🚀 지금 확인', '', 1430000.00, 7150),
(12598, 1, '📱 스마트폰 차량용 무선 충전 거치대', '', '🎬 흔들림 없는 자동 홀딩 시스템\n✨ 시동 꺼져도 열리는 예비 전력 탑재\n📌 전 차종 호환 대시보드형\n▶ 구매하기', '', 820000.00, 4100),
(12599, 1, '🧊 휴대용 제빙기 7분 급속 제빙', '', '💧 야외에서도 시원한 얼음 무한 공급\n✨ 자동 세척 기능으로 위생 관리\n📞 캠핑족 강력 추천 시즌템\n🚀 상담 신청', '', 210000.00, 1050),
(12600, 1, '🦾 손안마기 온열 지압 무선형', '', '💆 고생한 손을 위한 따뜻한 공기압\n💎 강도 3단계 조절 & 충전식 사용\n⚡ 명절 부모님 선물 1위\n▶ 혜택 보기', '', 1500000.00, 7500);
