INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12601, 1, '🎧 프로페셔널 모니터링 헤드폰', '', '🎵 원음 그대로의 감동을 전달하는 해상도\n💎 장시간 작업에도 편안한 벨벳 패드\n⚡ 스튜디오 전문가들의 필수 선택\n▶ 제품 상세 보기', '', 890000.00, 4450),
(12602, 1, '💻 고성능 그래픽카드 최신 모델', '', '✨ 압도적인 프레임으로 즐기는 AAA 게임\n🎯 트리플 팬 설계로 발열 완벽 제어\n🔥 한정 수량 특가 세일 진행 중\n🚀 지금 클릭', '', 280000.00, 1400),
(12603, 1, '⌚ 스마트워치 전용 가죽 스트랩', '', '🎨 클래식한 무드로 완성하는 데일리룩\n💎 이태리 천연 가죽의 부드러운 감촉\n📌 전 기종 호환 어댑터 무료 증정\n▶ 구경하기', '', 1570000.00, 7850),
(12604, 1, '🖱️ 인체공학 트랙볼 마우스', '', '🤫 손목을 움직이지 않아도 되는 편안함\n✨ 좁은 공간에서도 자유로운 컨트롤\n⚡ 사무직 필수 템 20% 할인\n▶ 확인하기', '', 960000.00, 4800),
(12605, 1, '🔋 100W 초고속 충전 케이블', '', '⚡ 노트북 충전도 문제없는 강력한 출력\n💎 단선 걱정 없는 메쉬 나일론 소재\n📌 E-Marker 칩 탑재로 안전한 충전\n🚀 바로 주문', '', 350000.00, 1750),
(12606, 1, '📷 미러리스 전용 광각 렌즈', '', '🎬 풍경 사진의 깊이를 더하는 화각\n🎯 빠르고 정확한 AF 시스템 탑재\n🎁 지금 구매 시 렌즈 필터 증정\n▶ 상세 보기', '', 1640000.00, 8200),
(12607, 1, '📺 스마트 사이니지 홍보용 디스플레이', '', '🏟️ 24시간 선명한 고화질 비즈니스 솔루션\n✨ 간편한 콘텐츠 관리 시스템 내장\n⚡ 매장 인테리어의 완성\n🚀 상담 신청하기', '', 1030000.00, 5150),
(12608, 1, '⌨️ 무소음 기계식 키보드 (적축)', '', '🎮 구름 위를 걷는 듯한 부드러운 타건감\n💎 오피스 환경에 최적화된 저소음 설계\n📌 RGB 백라이트 커스텀 가능\n▶ 구매하기', '', 420000.00, 2100),
(12609, 1, '📱 스마트폰 액정 보호 강화유리', '', '✨ 다이아몬드급 경도로 스크래치 방지\n🎯 지문 방지 코팅으로 언제나 깨끗하게\n💸 1+1 패키지 특별 구성\n🚀 바로 구매', '', 1710000.00, 8550),
(12610, 1, '🔈 하이엔드 북쉘프 스피커', '', '🎵 거실을 콘서트 홀로 만드는 사운드\n🎨 리얼 우드 마감의 고급스러운 디자인\n⚡ 오디오 매니아 추천 모델\n▶ 더 보기', '', 1100000.00, 5500),
(12611, 1, '🎮 무선 게이밍 컨트롤러 패드', '', '🔥 딜레이 없는 초저지연 무선 연결\n🎯 리얼한 진동 피드백 시스템\n📌 안드로이드/iOS/PC 완벽 지원\n🚀 지금 클릭', '', 490000.00, 2450),
(12612, 1, '🖥️ 울트라 와이드 21:9 모니터', '', '✨ 멀티태스킹에 최적화된 넓은 화면\n💎 영화 감상 시 압도적인 몰입감\n⚡ 신규 런칭 기념 특가 판매\n▶ 확인하기', '', 1780000.00, 8900),
(12613, 1, '🖨️ 무선 라벨 프린터 블루투스형', '', '📑 정리 정돈의 시작! 앱으로 간편 출력\n💸 주방, 서재, 아이 방 어디든 활용\n📌 전용 라벨지 3롤 증정\n🚀 지금 구매', '', 1170000.00, 5850),
(12614, 1, '🧥 스마트 워킹 패드 가정용', '', '✨ 층간 소음 걱정 없는 저진동 설계\n🎯 접어서 보관하는 슬림 디자인\n📞 무료 체험 신청 이벤트\n▶ 상담 받기', '', 560000.00, 2800),
(12615, 1, '🌬️ 타워형 무엽 선풍기 안전 설계', '', '💎 날개 없어 아이/반려동물에게 안전\n✨ 강력한 공기 정화 필터 탑재\n💸 시즌 오프 미리 준비 특가\n🚀 지금 확인', '', 1850000.00, 9250),
(12616, 1, '🧹 무선 물걸레 청소기 자동 세척', '', '🎯 버튼 하나로 걸레 세척부터 건조까지\n✨ 허리 숙일 필요 없는 인체공학 구조\n📌 주부들의 워너비 아이템\n▶ 더 보기', '', 1240000.00, 6200),
(12617, 1, '🧊 와인 셀러 12구 미니 사이즈', '', '🎨 와인의 풍미를 지키는 최적 온도 관리\n💎 저진동 저소음 시스템 적용\n⚡ 홈바 인테리어 필수 가전\n🚀 구매하기', '', 630000.00, 3150),
(12618, 1, '💧 스마트 IoT 온습도계 앱 연동', '', '✨ 외출해서도 집안 공기를 체크하세요\n🎯 에어컨/가습기 자동 제어 연동 가능\n📌 정밀 센서 탑재 모델\n▶ 확인하기', '', 1920000.00, 9600),
(12619, 1, '🍳 와플 & 샌드위치 메이커 2in1', '', '🍗 겉바속촉 브런치를 집에서 5분 만에\n💎 위생적인 분리형 플레이트\n🎁 레시피 가이드북 증정\n🚀 지금 주문', '', 1310000.00, 6550),
(12620, 1, '☕ 전자동 에스프레소 머신', '', '☕ 원두 분쇄부터 추출까지 한 번에\n✨ 나만의 커스텀 레시피 저장\n⚡ 렌탈보다 합리적인 일시불 특가\n▶ 구경하기', '', 700000.00, 3500),
(12621, 1, '🏋️ 스마트 사이클 홈트레이닝 패키지', '', '📈 실시간 전 세계 유저와 라이딩 대결\n✨ 칼로리 분석 및 전문 강사 코칭\n📌 전용 매트 증정 이벤트\n🚀 지금 구매', '', 1990000.00, 9950),
(12622, 1, '💇 두피 마사지기 방수 진동 기능', '', '✨ 샴푸와 동시에 시원한 두피 케어\n🎯 탈모 예방 및 혈액순환 도움\n⚡ 특가 판매 종료 임박\n▶ 제품 보기', '', 1380000.00, 6900),
(12623, 1, '💆 다리 공기압 마사지기 세트', '', '🔋 퉁퉁 부은 다리를 위한 힐링 타임\n💎 붓기 완화 및 피로 회복 도움\n📌 부모님 명절 선물 추천\n🚀 지금 클릭', '', 770000.00, 3850),
(12624, 1, '📽️ 4K 레이저 빔프로젝터', '', '🎬 낮에도 선명한 압도적 밝기\n✨ 자동 초점 및 스마트 TV 기능\n🎁 전용 가방 포함 풀세트\n▶ 확인하기', '', 160000.00, 800),
(12625, 1, '👜 하드쉘 테크 파우치 충격 보호', '', '🎨 케이블, 보조배터리 한 번에 정리\n💎 스크래치에 강한 내구성 소재\n⚡ 디지털 노마드 필수 아이템\n🚀 바로 주문', '', 1450000.00, 7250),
(12626, 1, '📻 인테리어 턴테이블 스피커', '', '🎵 감성 가득한 레트로 오브제\n✨ 블루투스 스피커 기능 내장\n📌 인스타그램 화제 아이템\n▶ 구경하기', '', 840000.00, 4200),
(12627, 1, '📏 디지털 줄자 레이저 거리계', '', '🛠️ 최대 40m까지 오차 없이 측정\n✨ 넓이, 부피 자동 계산 기능\n⚡ 이사 준비 필수 공구\n🚀 지금 확인', '', 230000.00, 1150),
(12628, 1, '🏮 캠핑용 파워뱅크 대용량', '', '✨ 노지 캠핑에서도 전기 걱정 제로\n💎 멀티 포트로 동시 5대 충전\n📌 안전한 인산철 배터리 사용\n▶ 구매하기', '', 1520000.00, 7600),
(12629, 1, '🎙️ 노이즈 캔슬링 콘덴서 마이크', '', '🎧 키보드 소음 차단! 목소리만 선명하게\n✨ ASMR 및 고품질 녹음 지원\n⚡ 쇼크 마운트 포함 구성\n🚀 지금 클릭', '', 910000.00, 4550),
(12630, 1, '🔌 스마트 멀티탭 앱 제어 가능', '', '⚡ 깜빡한 전등, 밖에서 끄세요\n💎 대기전력 차단으로 전기세 절약\n📌 시간 예약 타이머 기능\n▶ 더 보기', '', 300000.00, 1500),
(12631, 1, '🚲 전기 스쿠터 친환경 퍼스널 모빌리티', '', '⚡ 한 번 충전으로 동네 한 바퀴 충분\n💎 번호판 등록 필요 없는 스마트 모델\n📌 사후 관리 AS 보장\n🚀 지금 확인', '', 1590000.00, 7950),
(12632, 1, '🛴 어린이용 전동 킥보드 안전 모델', '', '✨ 속도 제한 설정으로 안전하게\n🎯 화려한 LED 휠로 시인성 확보\n⚡ 어린이날 선물 강력 추천\n▶ 바로 구매', '', 980000.00, 4900),
(12633, 1, '🌡️ 비접촉 레이저 온도계 요리/산업용', '', '✨ 기름 온도, 오븐 온도 한 번에 측정\n💎 전문가가 선택한 정밀 기기\n📌 공식 정품 특별 할인가\n🚀 지금 주문', '', 370000.00, 1850),
(12634, 1, '🧊 미니 무선 냉풍기 1인용', '', '🌬️ 물만 넣으면 시원한 얼음 바람\n✨ 보조배터리로 야외 사용 가능\n⚡ 여름 미리 준비 파격 할인\n▶ 더 보기', '', 1660000.00, 8300),
(12635, 1, '🍞 자동 회전 꼬치 구이기', '', '✨ 집에서 즐기는 양꼬치와 바베큐\n💎 연기 걱정 없는 하이라이트 방식\n📌 홈파티 인기 1순위\n🚀 지금 클릭', '', 1050000.00, 5250),
(12636, 1, '💧 음파 전동 칫솔 미백 모드', '', '🦷 분당 4만 회 진동으로 플라그 제거\n✨ 잇몸 자극 없는 세밀한 세정\n⚡ 지금 사면 리필 헤드 4개\n▶ 확인하기', '', 440000.00, 2200),
(12637, 1, '🧔 바디 트리머 겨드랑이/다리용', '', '✨ 깔끔한 그루밍을 위한 필수템\n🎯 날 베임 방지 세이프티 가드\n📌 완전 방수로 샤워 시 사용 가능\n🚀 바로 구매', '', 1730000.00, 8650),
(12638, 1, '🎵 수면용 화이트 노이즈 머신', '', '🎧 깊은 잠을 유도하는 24가지 소리\n✨ 무드등 기능으로 편안한 분위기\n⚡ 층간 소음 차단 효과\n▶ 구경하기', '', 1120000.00, 5600),
(12639, 1, '💼 가죽 메신저 백 13인치 노트북용', '', '✨ 비즈니스와 캐주얼을 동시에\n💎 최고급 소가죽의 프리미엄 감성\n📌 어깨 패드로 편안한 착용감\n🚀 지금 확인', '', 510000.00, 2550),
(12640, 1, '💾 고속 CFexpress 메모리카드', '', '🚀 8K 영상 전문 촬영용 고스펙\n✨ 압도적인 쓰기 속도 보장\n⚡ 전문 작가들이 선호하는 브랜드\n▶ 구매하기', '', 1800000.00, 9000),
(12641, 1, '👔 의류 건조기 미니 3kg', '', '✨ 수건, 속옷 바로바로 건조하세요\n💎 좁은 집에도 쏙 들어가는 사이즈\n📌 자취생 필수 삶의 질 상승템\n🚀 지금 주문', '', 1190000.00, 5950),
(12642, 1, '🥣 진공 블렌더 산화 방지 기술', '', '✨ 시간이 지나도 층 분리 없는 주스\n🎯 소음 방지 커버로 조용한 사용\n⚡ 건강 관리 시작 패키지\n▶ 더 보기', '', 580000.00, 2900),
(12643, 1, '🧴 초음파 과일 채소 세척기', '', '💎 잔류 농약 99% 제거하는 미세 진동\n✨ 육류 핏물 제거에도 효과적\n📌 주방 건강 가전 신제품\n🚀 바로 클릭', '', 1870000.00, 9350),
(12644, 1, '🎸 사일런트 기타 야간 연습용', '', '🎵 헤드폰 연결로 조용하게 연주\n✨ 슬림한 바디로 뛰어난 휴대성\n⚡ 버스킹용 앰프 연결 지원\n▶ 확인하기', '', 1260000.00, 6300),
(12645, 1, '🎹 접이식 88건반 디지털 피아노', '', '✨ 공간 활용 만점! 반으로 접는 피아노\n🎯 내장 배터리로 야외 연주 가능\n🎁 전용 가방 포함 기획전\n🚀 지금 구매', '', 650000.00, 3250),
(12646, 1, '🔦 자가발전 비상용 라디오 랜턴', '', '✨ 건전지 없어도 핸들 돌리면 작동\n💎 재난 대비 필수 SOS 알람 기능\n📌 보조배터리 충전 기능 포함\n▶ 구경하기', '', 1940000.00, 9700),
(12647, 1, '🕶️ 오디오 스마트 안경 오픈형', '', '🎧 귀를 막지 않아 주변 소리도 안전하게\n✨ 고품질 마이크로 선명한 통화\n⚡ 스타일리시한 디자인\n🚀 지금 확인', '', 1330000.00, 6650),
(12648, 1, '📱 스마트폰 가슴 마운트 액션캠용', '', '🎬 1인칭 시점의 역동적인 영상 촬영\n✨ 등산, 자전거 라이딩 필수 아이템\n📌 전 기종 스마트폰 홀더 포함\n▶ 구매하기', '', 720000.00, 3600),
(12649, 1, '🧊 대용량 업소용 제빙기 렌탈', '', '💧 하루 50kg 얼음 생산 파워\n✨ 카페 창업 초기 비용 절감 솔루션\n📞 정기 방문 점검 서비스 포함\n🚀 상담 신청', '', 110000.00, 550),
(12650, 1, '🦾 목 어깨 마사지기 주무름 방식', '', '💆 전문가의 손길처럼 시원한 압력\n💎 온열 기능으로 근육 이완 효과\n⚡ 명절 선물 세트 주문 폭주\n▶ 혜택 보기', '', 1400000.00, 7000);
