INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12651, 1, '🎧 액티브 노이즈 캔슬링 헤드폰', '', '🎵 소음은 지우고 음악에만 몰입하세요\n💎 고해상도 오디오 코덱 LDAC 지원\n⚡ 최대 40시간 재생 가능한 배터리\n▶ 제품 상세 보기', '', 790000.00, 3950),
(12652, 1, '💻 커스텀 수랭 PC 빌드 서비스', '', '✨ 극강의 퍼포먼스와 화려한 감성\n🎯 전문가의 정밀한 조립 및 테스트\n🔥 오버클럭 최적화 세팅 무료 제공\n🚀 지금 견적 문의', '', 180000.00, 900),
(12653, 1, '⌚ 티타늄 스마트워치 스트랩', '', '🎨 가볍지만 강력한 내구성의 완성\n💎 정교한 링크 디자인으로 완벽한 핏\n📌 조절 도구 포함 패키지 증정\n▶ 구경하기', '', 1470000.00, 7350),
(12654, 1, '🖱️ 매크로 지원 게이밍 마우스', '', '🎮 승리를 부르는 0.1ms 반응 속도\n✨ 전용 소프트웨어로 버튼 커스텀\n⚡ 신규 모델 출시 기념 특가\n▶ 확인하기', '', 860000.00, 4300),
(12655, 1, '🔋 태양광 충전 보조배터리 30000mAh', '', '⚡ 빛만 있으면 어디서든 자가 충전\n💎 캠핑/재난 대비 필수 대용량\n📌 4포트 동시 충전 및 플래시 내장\n🚀 바로 주문', '', 250000.00, 1250),
(12656, 1, '📷 짐벌 일체형 포켓 카메라', '', '🎬 흔들림 없는 브이로그 인생샷\n🎯 얼굴 추적 AI 트래킹 모드 탑재\n🎁 전용 마이크 세트 추가 증정\n▶ 상세 보기', '', 1540000.00, 7700),
(12657, 1, '📺 울트라 초단초점 4K 프로젝터', '', '🏟️ 벽 앞에서도 구현되는 120인치 화면\n✨ 홈시어터의 끝판왕 스펙\n⚡ 설치비 전액 지원 이벤트\n🚀 상담 신청하기', '', 930000.00, 4650),
(12658, 1, '⌨️ 75% 커스텀 키보드 알루미늄 하우징', '', '💎 묵직한 타건감과 프리미엄 사운드\n✨ 취향대로 바꾸는 기계식 스위치\n📌 한정 수량 베어본 키트 입고\n▶ 구매하기', '', 320000.00, 1600),
(12659, 1, '📱 프라이버시 보호 강화유리', '', '✨ 옆사람은 볼 수 없는 완벽 보안\n🎯 지문 방지 및 스크래치 내구성\n💸 2매 세트 파격 할인가\n🚀 바로 구매', '', 1610000.00, 8050),
(12660, 1, '🔈 빈티지 우드 블루투스 스피커', '', '🎵 아날로그 감성과 현대적 기술의 조화\n🎨 인테리어 효과가 뛰어난 디자인\n⚡ 집들이 선물 추천 아이템\n▶ 더 보기', '', 1000000.00, 5000),
(12661, 1, '🎮 휴대용 PC 게이밍 콘솔', '', '🔥 언제 어디서나 즐기는 스팀 게임\n🎯 고성능 프로세서와 밝은 디스플레이\n📌 전용 독(Dock) 포함 기획전\n🚀 지금 클릭', '', 390000.00, 1950),
(12662, 1, '🖥️ 5K 전문가용 모니터 DCI-P3 99%', '', '✨ 디자이너와 편집자를 위한 정확한 색감\n💎 높이 및 회전 조절 스탠드 포함\n⚡ 신규 가입 시 5만원 즉시 할인\n▶ 확인하기', '', 1680000.00, 8400),
(12663, 1, '🖨️ 스마트폰 전용 미니 라벨기', '', '📑 다이어리 꾸미기부터 주방 정리까지\n💸 잉크 없이 열로 찍어내는 방식\n📌 전용 케이스 증정 프로모션\n🚀 지금 구매', '', 1070000.00, 5350),
(12664, 1, '🧥 전동 킥보드 고성능 듀얼 모터', '', '✨ 최대 시속 25km 안전 주행 설계\n🎯 경사로도 가뿐한 강력한 등판 능력\n📞 시승 체험 및 AS 보증 서비스\n▶ 상담 받기', '', 460000.00, 2300),
(12665, 1, '🌬️ 스마트 IoT 공기청정기', '', '💎 미세먼지 수치를 폰으로 실시간 확인\n✨ H13 등급 헤파필터로 완벽 정화\n💸 필터 정기 구독 할인 혜택\n🚀 지금 확인', '', 1750000.00, 8750),
(12666, 1, '🧹 로봇청소기 스테이션 일체형', '', '🎯 먼지 비움부터 걸레 세척까지 자동\n✨ 장애물 회피 LiDAR 센서 탑재\n📌 삶의 질을 높이는 가사 도우미\n▶ 더 보기', '', 1140000.00, 5700),
(12667, 1, '🧊 차량용 빌트인 공기청정기', '', '🎨 드라이브를 쾌적하게 만드는 기술\n💎 미세먼지 및 담배 냄새 제거\n⚡ 컵홀더형 콤팩트 디자인\n🚀 구매하기', '', 530000.00, 2650),
(12668, 1, '💧 스마트 가습기 살균 모드 탑재', '', '✨ 세균 걱정 없는 고온 가열식 살균\n🎯 자동 습도 조절로 최적의 환경 유지\n📌 세척이 간편한 분리형 구조\n▶ 확인하기', '', 1820000.00, 9100),
(12669, 1, '🍳 에어프라이어 대용량 오븐형', '', '🍗 로티세리 기능으로 통닭구이 완성\n💎 내부가 보이는 강화유리 도어\n🎁 전용 조리 도구 5종 증정\n🚀 지금 주문', '', 1210000.00, 6050),
(12670, 1, '☕ 캡슐 커피 머신 런칭 기념', '', '☕ 버튼 한 번으로 즐기는 홈카페\n✨ 전 세계 명품 원두 캡슐 호환\n⚡ 지금 사면 시음용 캡슐 20팩\n▶ 구경하기', '', 600000.00, 3000),
(12671, 1, '🏋️ 스마트 웨어러블 자세 교정기', '', '📈 거북목 방지! 실시간 진동 알림\n✨ 옷 안에 착용해도 티 나지 않음\n📌 사무직/학생 필수 추천\n🚀 지금 구매', '', 1890000.00, 9450),
(12672, 1, '💇 전문가용 헤어 드라이기 2000W', '', '✨ 음이온 방출로 머릿결 손상 최소화\n🎯 강력한 풍량으로 빠른 건조\n⚡ 노즐 3종 포함 풀세트\n▶ 제품 보기', '', 1280000.00, 6400),
(12673, 1, '💆 다목적 마사지건 6종 헤드', '', '🔋 근육 깊숙한 곳까지 시원하게\n💎 저소음 설계로 밤에도 조용하게\n📌 운동 후 근육 피로 회복 필수\n🚀 지금 클릭', '', 670000.00, 3350),
(12674, 1, '📽️ 휴대용 미니 빔프로젝터 안드로이드', '', '🎬 자체 앱 구동으로 연결 선 없이\n✨ 300g 초경량으로 캠핑용 제격\n🎁 전용 스크린 사은품 증정\n▶ 확인하기', '', 1960000.00, 9800),
(12675, 1, '👜 맥북 전용 가죽 슬리브', '', '🎨 슬림하고 우아한 보호 솔루션\n💎 부드러운 스웨이드 안감 처리\n⚡ 세련된 3가지 어반 컬러\n🚀 바로 주문', '', 1350000.00, 6750),
(12676, 1, '📻 올인원 오디오 CD/LP/BT 지원', '', '🎵 과거와 현재를 잇는 음악 감상\n✨ 고출력 스피커 내장으로 웅장하게\n📌 거실 인테리어 포인트 가전\n▶ 구경하기', '', 740000.00, 3700),
(12677, 1, '📏 스마트 레이저 수평계 360도', '', '🛠️ 수직, 수평을 한 번에 정밀 측정\n✨ 셀프 인테리어의 완성도 상승\n⚡ 강력 자석 거치대 포함\n🚀 지금 확인', '', 130000.00, 650),
(12678, 1, '🏮 캠핑용 그리들 팬 솥뚜껑 타입', '', '✨ 고기 굽기부터 볶음밥까지 만능\n💎 눌어붙지 않는 논스틱 코팅\n📌 전용 보관 가방 세트 판매\n▶ 구매하기', '', 1420000.00, 7100),
(12679, 1, '🎙️ 팟캐스트/방송용 마이크 암 세트', '', '🎧 깔끔한 데스크 환경을 위한 거치대\n✨ 소음 차단 팝필터 기본 포함\n⚡ 유튜버 입문자용 가성비 패키지\n🚀 지금 클릭', '', 810000.00, 4050),
(12680, 1, '🔌 질화갈륨(GaN) 120W 멀티 충전기', '', '⚡ 노트북 2대 동시 초고속 충전 지원\n💎 작고 가벼운 휴대용 끝판왕\n📌 안전 인증 완료 및 과열 방지\n▶ 더 보기', '', 200000.00, 1000),
(12681, 1, '🚲 전기 자전거 접이식 도심형', '', '⚡ 출퇴근이 즐거워지는 스마트 이동\n💎 배터리 탈부착으로 간편한 충전\n📌 헬멧 및 자물쇠 증정 혜택\n🚀 지금 확인', '', 1490000.00, 7450),
(12682, 1, '🛴 어린이 전동 카트 서킷 모델', '', '✨ 집 앞 공원을 레이싱 경기장으로\n🎯 속도 조절 및 안전 벨트 탑재\n⚡ 아이들이 가장 좋아하는 선물\n▶ 바로 구매', '', 880000.00, 4400),
(12683, 1, '🌡️ 실내 공기질 모니터링 기기', '', '✨ 이산화탄소, 휘발성 유기화합물 체크\n💎 환기 시점을 알려주는 스마트 램프\n📌 가족 건강 지킴이 필수템\n🚀 지금 주문', '', 270000.00, 1350),
(12684, 1, '🧊 무선 핸디 선풍기 거치형', '', '🌬️ 강력한 바람과 보조배터리 기능\n✨ 데스크탑 거치로 사무실용 제격\n⚡ 저소음 BLDC 모터 사용\n▶ 더 보기', '', 1560000.00, 7800),
(12685, 1, '🍞 스팀 토스터기 갓 구운 빵 식감', '', '✨ 겉은 바삭, 속은 촉촉한 마법\n💎 죽은 빵도 살려내는 스팀 기술\n📌 주방 인테리어 감성 가전\n🚀 지금 클릭', '', 950000.00, 4750),
(12686, 1, '💧 휴대용 구강세정기 무선형', '', '🦷 칫솔이 닿지 않는 곳까지 시원하게\n✨ 3가지 수압 모드 및 방수 지원\n⚡ 여행용 파우치 무료 증정\n▶ 확인하기', '', 340000.00, 1700),
(12687, 1, '🧔 프리미엄 전기 면도기 건습식', '', '✨ 굴곡진 턱선도 매끄럽게 밀착 면도\n🎯 자동 세척 및 충전 스테이션 포함\n📌 남자친구 선물 만족도 1위\n🚀 바로 구매', '', 1630000.00, 8150),
(12688, 1, '🎵 골전도 수면 안대 블루투스', '', '🎧 귀 통증 없이 즐기는 힐링 사운드\n✨ 빛 완벽 차단으로 깊은 잠 유도\n⚡ 불면증 탈출 도우미\n▶ 구경하기', '', 1020000.00, 5100),
(12689, 1, '💼 비즈니스 테크 백팩 확장형', '', '✨ 출장 갈 땐 늘리고 평소엔 슬림하게\n💎 방수 코팅 및 TSA 잠금장치 탑재\n📌 16인치 노트북 수납 공간\n🚀 지금 확인', '', 410000.00, 2050),
(12690, 1, '💾 외장 SSD 2TB 초소형 디자인', '', '🚀 HDD보다 10배 빠른 데이터 전송\n✨ 신용카드보다 작은 극강의 휴대성\n⚡ 소중한 자료 안전하게 보관\n▶ 구매하기', '', 1700000.00, 8500),
(12691, 1, '👔 핸디형 보풀 제거기 충전식', '', '✨ 헌 옷을 새 옷처럼 깔끔하게\n💎 강력한 6중 회전 칼날 탑재\n📌 니트, 코트 등 모든 의류 호환\n🚀 지금 주문', '', 1090000.00, 5450),
(12692, 1, '🥣 수비드 머신 가정용 요리 혁명', '', '✨ 스테이크 전문점의 맛을 집에서\n🎯 0.1도 단위 정밀 온도 제어\n⚡ 저칼로리 건강식 조리에 제격\n▶ 더 보기', '', 480000.00, 2400),
(12693, 1, '🧴 전동 창문 청소기 로봇형', '', '💎 손이 닿지 않는 외부 창문도 반짝\n✨ 강력한 흡착력으로 낙하 방지\n📌 아파트 거실 창 청소 필수품\n🚀 바로 클릭', '', 1770000.00, 8850),
(12694, 1, '🎸 미니 기타 앰프 블루투스 겸용', '', '🎵 작지만 강력한 사운드 출력\n✨ 평소엔 스피커로, 연습 땐 앰프로\n⚡ 충전식으로 야외에서도 사용 가능\n▶ 확인하기', '', 1160000.00, 5800),
(12695, 1, '🎹 롤업 피아노 휴대용 실리콘', '', '✨ 가방에 쏙! 돌돌 말아 보관하세요\n🎯 야외 버스킹 및 아이들 놀이용\n🎁 전용 어댑터 포함 구성\n🚀 지금 구매', '', 550000.00, 2750),
(12696, 1, '🔦 자석 고정식 작업등 LED', '', '✨ 자동차 정비, 캠핑 등 다목적 활용\n💎 강력한 자석과 360도 회전 훅\n📌 USB 충전식 고휘도 라이트\n▶ 구경하기', '', 1840000.00, 9200),
(12697, 1, '🕶️ 오버사이즈 선글라스 편광 렌즈', '', '🎧 눈부심 방지와 자외선 완벽 차단\n✨ 얼굴이 작아 보이는 트렌디 핏\n⚡ 여행 필수 패션 아이템\n🚀 지금 확인', '', 1230000.00, 6150),
(12698, 1, '📱 스마트폰 삼각대 리모컨 세트', '', '🎬 혼자서도 완벽한 전신 샷 촬영\n✨ 알루미늄 소재로 튼튼한 지지력\n📌 360도 회전 홀더 기본 제공\n▶ 구매하기', '', 620000.00, 3100),
(12699, 1, '🧊 가정용 제빙기 위생 살균 기능', '', '💧 불순물 없는 투명한 얼음 생성\n✨ 자동 세척 및 UV 살균 탑재\n📞 얼음 정수기보다 경제적\n🚀 상담 신청', '', 1910000.00, 9550),
(12700, 1, '🦾 전신 안마 의자 콤팩트 모델', '', '💆 좁은 방에도 쏙! 공간 효율 디자인\n💎 무중력 모드 및 온열 마사지\n⚡ 가성비 끝판왕 특가 기획전\n▶ 혜택 보기', '', 1300000.00, 6500);
