INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12701, 1, '🎧 무선 하이엔드 이어폰 (LDAC 지원)', '', '🎵 유선의 감동을 무선으로 즐기세요\n💎 고해상도 코덱으로 놓치는 음 없이 선명하게\n⚡ 업계 최고 수준의 노이즈 캔슬링 탑재\n▶ 제품 상세 보기', '', 690000.00, 3450),
(12702, 1, '💻 고주사율 게이밍 모니터 240Hz', '', '✨ 찰나의 순간도 놓치지 않는 부드러움\n🎯 승리를 위한 0.5ms 응답 속도\n🔥 프로 게이머가 선택한 바로 그 모델\n🚀 지금 클릭', '', 1980000.00, 9900),
(12703, 1, '⌚ 스마트워치 러버 스트랩 스포츠용', '', '🎨 땀과 오염에 강한 고품질 실리콘\n💎 운동 중에도 피부 자극 없는 부드러움\n📌 다채로운 12가지 컬러 라인업\n▶ 구경하기', '', 1370000.00, 6850),
(12704, 1, '🖱️ 저소음 무선 마우스 슬림형', '', '🤫 도서관이나 카페에서도 매너 있게\n✨ 가방에 쏙 들어가는 초슬림 디자인\n⚡ 멀티 페어링으로 기기 간 전환 자유\n▶ 확인하기', '', 760000.00, 3800),
(12705, 1, '🔋 맥세이프 호환 3in1 무선 충전기', '', '⚡ 폰, 워치, 이어폰을 한 번에 충전\n💎 데스크를 깔끔하게 만드는 미니멀 디자인\n📌 과충전 방지 안전 회로 내장\n🚀 바로 주문', '', 150000.00, 750),
(12706, 1, '📷 브이로그용 미러리스 카메라 세트', '', '🎬 누구나 쉽게 찍는 4K 고화질 영상\n🎯 인물 눈동자를 쫓는 실시간 AF\n🎁 지금 구매 시 추가 배터리 증정\n▶ 상세 보기', '', 1440000.00, 7200),
(12707, 1, '📺 시네마틱 사운드바 돌비 애트모스', '', '🏟️ 거실 전체를 감싸는 입체적인 음향\n✨ 무선 서브우퍼로 강력한 저음 구현\n⚡ 영화관의 감동을 집에서 느껴보세요\n🚀 지금 확인', '', 830000.00, 4150),
(12708, 1, '⌨️ 로우 프로파일 기계식 키보드', '', '💎 슬림한 두께와 경쾌한 타건감의 조화\n✨ 손목 부담을 줄여주는 낮은 높이 설계\n📌 유무선 겸용 및 화이트 LED 탑재\n▶ 구매하기', '', 220000.00, 1100),
(12709, 1, '📱 스마트폰 짐벌 3축 손떨림 방지', '', '✨ 걸으면서 찍어도 영화처럼 매끄럽게\n🎯 조이스틱 컨트롤로 자유로운 각도 조절\n💸 신규 가입 시 10% 추가 할인\n🚀 바로 구매', '', 1510000.00, 7550),
(12710, 1, '🔈 캠핑용 빈티지 랜턴 스피커', '', '🎵 감성 캠핑의 완성! 조명과 음악을 동시에\n🎨 앤티크한 디자인으로 인테리어 만점\n⚡ 야외 활동 최적화 생활 방수 지원\n▶ 더 보기', '', 900000.00, 4500),
(12711, 1, '🎮 아케이드 조이스틱 격투 게임용', '', '🔥 오락실의 손맛을 그대로 재현\n🎯 빠른 커맨드 입력과 묵직한 지지력\n📌 PC 및 최신 콘솔 완벽 호환\n🚀 지금 클릭', '', 290000.00, 1450),
(12712, 1, '🖥️ 휴대용 모니터 15.6인치 FHD', '', '✨ 노트북 옆에 하나 더! 듀얼 모니터 완성\n💎 C-Type 케이블 하나로 전원과 영상 연결\n⚡ 출장/재택근무 필수 아이템\n▶ 확인하기', '', 1580000.00, 7900),
(12713, 1, '🖨️ 포토 키오스크급 사진 인화기', '', '📑 폰 속 사진을 선명한 실물로 간편 출력\n💸 변색 걱정 없는 특수 코팅 방식\n📌 전용 인화지 번들 세트 특가\n🚀 지금 구매', '', 970000.00, 4850),
(12714, 1, '🧥 스마트 체지방계 앱 연동형', '', '✨ 12가지 신체 데이터 정밀 측정\n🎯 온 가족 건강 관리를 앱 하나로\n📞 필라테스/헬스장 납품 공식 모델\n▶ 제품 보기', '', 360000.00, 1800),
(12715, 1, '🌬️ 서큘레이터 겸용 무선 선풍기', '', '💎 선 없이 자유롭게! 최대 20시간 사용\n✨ 상하좌우 입체 회전으로 입체 냉방\n💸 얼리버드 구매 고객 사은품 증정\n🚀 지금 확인', '', 1650000.00, 8250),
(12716, 1, '🧹 핸디형 무선 청소기 강력 흡입', '', '🎯 틈새 먼지부터 과자 부스러기까지 한 번에\n✨ 자동차 실내 청소에도 최적화된 사이즈\n📌 고성능 BLDC 모터 탑재\n▶ 더 보기', '', 1040000.00, 5200),
(12717, 1, '🧊 미니 화장품 냉장고 저소음', '', '🎨 화장품 최적 온도로 신선하게 보관\n💎 팩, 앰플 효능을 극대화하는 쿨링링\n⚡ 침실에 두어도 조용한 무소음급 설계\n🚀 구매하기', '', 430000.00, 2150),
(12718, 1, '💧 스마트 공기 가습기 대용량', '', '✨ 초음파식 분무량 조절 및 자동 정지\n🎯 세척이 간편한 통세척 구조\n📌 아이 방 적정 습도 유지 아이템\n▶ 확인하기', '', 1720000.00, 8600),
(12719, 1, '🍳 전기 그릴 홈파티용 연기 저감', '', '🍗 고기는 맛있게, 연기는 쏙 흡입\n💎 눌어붙지 않는 와이드 불판\n🎁 전용 보관 가방 증정 이벤트\n🚀 지금 주문', '', 1110000.00, 5550),
(12720, 1, '☕ 콜드브루 메이커 추출 키트', '', '☕ 집에서도 간편하게 즐기는 진한 풍미\n✨ 기다림의 미학, 깔끔한 뒷맛\n⚡ 카페 퀄리티 원두 포함 패키지\n▶ 구경하기', '', 500000.00, 2500),
(12721, 1, '🏋️ 스마트 복근 운동 기구 슬라이드', '', '📈 카운트와 타이머 기능으로 체계적 운동\n✨ 자동 리턴 기능으로 허리 부상 방지\n📌 홈트족 추천 갓성비 모델\n🚀 지금 구매', '', 1790000.00, 8950),
(12722, 1, '💇 휴대용 구강세정기 제트 수압', '', '✨ 칫솔질로 부족한 치아 사이 완벽 세정\n🎯 잇몸 마사지 효과로 구강 건강 증진\n⚡ 충전식 무선 타입으로 여행 시 편리\n▶ 확인하기', '', 1180000.00, 5900),
(12723, 1, '💆 목/어깨 무선 마사지기 온열형', '', '🔋 경직된 근육을 풀어주는 부드러운 손길\n💎 입체적인 주무름 방식으로 시원하게\n📌 직장인 선물 선호도 1위\n🚀 지금 클릭', '', 570000.00, 2850),
(12724, 1, '📽️ 시네마 빔프로젝터 안드로이드 OS', '', '🎬 넷플릭스, 유튜브 연결 없이 바로 감상\n✨ 자동 키스톤으로 화면 맞춤 고민 해결\n🎁 전용 삼각대 무료 증정\n▶ 확인하기', '', 1860000.00, 9300),
(12725, 1, '👜 맥북용 하드쉘 투명 케이스', '', '🎨 맥북 고유의 디자인을 살리는 투명함\n💎 충격과 스크래치로부터 완벽 보호\n⚡ 통풍구 설계로 발열 걱정 제로\n🚀 바로 주문', '', 1250000.00, 6250),
(12726, 1, '📻 턴테이블 블루투스 송수신 지원', '', '🎵 LP도 듣고 스마트폰 음악도 듣고\n✨ 입문자에게 추천하는 올인원 모델\n📌 감성적인 화이트 우드 컬러\n▶ 구경하기', '', 640000.00, 3200),
(12727, 1, '📏 디지털 각도기 경사계', '', '🛠️ 목공, DIY 필수! 소수점 단위 정밀 측정\n✨ 강력한 자석으로 고정 가능\n⚡ 전문가가 사용하는 공식 브랜드\n🚀 지금 확인', '', 1930000.00, 9650),
(12728, 1, '🏮 캠핑용 가스 버너 고화력 3구', '', '✨ 강풍에도 끄떡없는 바람막이 내장\n💎 한꺼번에 여러 요리가 가능한 멀티형\n📌 전용 하드 케이스 포함 구성\n▶ 구매하기', '', 1320000.00, 6600),
(12729, 1, '🎙️ 콘덴서 마이크 풀세트 입문용', '', '🎧 목소리를 생생하게 담는 고감도 센서\n✨ 팝필터와 붐 암 포함 풀패키지\n⚡ 1인 방송/유튜브 시작을 응원합니다\n🚀 지금 클릭', '', 710000.00, 3550),
(12730, 1, '🔌 스마트 타이머 플러그 앱 제어', '', '⚡ 설정한 시간에 전원 자동 차단\n💎 과전류 방지로 화재 예방 및 절전\n📌 스마트 홈 구축의 첫걸음\n▶ 더 보기', '', 100000.00, 500),
(12731, 1, '🚲 자전거용 속도계 GPS 연동', '', '⚡ 주행 거리, 속도, 고도까지 한눈에\n💎 라이딩 기록을 스마트폰 앱으로 저장\n📌 야간 가독성 높은 백라이트 지원\n🚀 지금 확인', '', 1390000.00, 6950),
(12732, 1, '🛴 전동 밸런스 보드 자이로 센서', '', '✨ 체중 이동만으로 자유로운 주행\n🎯 블루투스 스피커와 LED 라이트 탑재\n⚡ 신개념 퍼스널 모빌리티 체험\n▶ 바로 구매', '', 780000.00, 3900),
(12733, 1, '🌡️ 비접촉식 적외선 온도계', '', '✨ 아이 체온부터 요리 온도까지 한 번에\n💎 1초 만에 측정하는 고정밀 센서\n📌 가정 상비용 필수 아이템\n🚀 지금 주문', '', 170000.00, 850),
(12734, 1, '🧊 탁상용 미니 에어컨 수냉식', '', '🌬️ 얼음물만 넣으면 즉시 시원한 바람\n✨ 필터 교체 없는 반영구적 사용\n⚡ 사무실 책상 위 나만의 냉방\n▶ 더 보기', '', 1460000.00, 7300),
(12735, 1, '🍞 핸드 블렌더 5in1 멀티 세트', '', '✨ 믹싱, 다지기, 거품기까지 이 기기 하나로\n💎 스테인리스 칼날로 내구성과 위생 확보\n📌 이유식 준비하는 맘 필수템\n🚀 지금 클릭', '', 850000.00, 4250),
(12736, 1, '💧 칫솔 살균기 휴대용 UV-C', '', '🦷 가방 속 칫솔을 세균으로부터 보호\n✨ 3분 만에 99.9% 살균 완료\n⚡ 충전식으로 언제 어디서나 위생적으로\n▶ 확인하기', '', 240000.00, 1200),
(12737, 1, '🧔 바디 면도기 트리머 올인원', '', '✨ 머리부터 발끝까지 깔끔한 그루밍\n🎯 길이 조절 빗으로 정교한 스타일링\n📌 완전 방수로 샤워 중 사용 가능\n🚀 바로 구매', '', 1530000.00, 7650),
(12738, 1, '🎵 수면용 화이트 노이즈 블루투스 스피커', '', '🎧 깊은 잠을 유도하는 편안한 자연의 소리\n✨ 부드러운 무드등 기능으로 심신 안정\n⚡ 아이 잠재울 때 효과 만점\n▶ 구경하기', '', 920000.00, 4600),
(12739, 1, '💼 카메라 백팩 숄더 겸용 파티션', '', '✨ 렌즈와 바디를 안전하게 수납하는 칸막이\n💎 생활 방수 및 삼각대 거치 기능\n📌 출사 나가는 사진가들의 선택\n🚀 지금 확인', '', 310000.00, 1550),
(12740, 1, '💾 고성능 외장 하드 4TB 대용량', '', '🚀 방대한 영상 자료도 넉넉하게 보관\n✨ 충격 흡수 설계로 소중한 데이터 보호\n⚡ 자동 백업 소프트웨어 제공\n▶ 구매하기', '', 1600000.00, 8000),
(12741, 1, '👔 스팀 다리미 2in1 스탠드형', '', '✨ 옷걸이째로 쓱쓱- 수평 다림질도 가능\n💎 99% 살균 탈취 효과로 코트 관리\n📌 퀵 스타트 예열 시스템 탑재\n🚀 지금 주문', '', 990000.00, 4950),
(12742, 1, '🥣 진공 포장기 가정용 밀봉', '', '✨ 식재료를 더 신선하고 오래 보관하세요\n🎯 수비드 요리 준비에도 필수 아이템\n⚡ 전용 롤 2개 추가 증정\n▶ 더 보기', '', 380000.00, 1900),
(12743, 1, '🧴 초음파 안경 세척기 멀티용', '', '💎 미세한 진동으로 안경 틈새 때까지 쏙\n✨ 시계, 액세서리 세척에도 탁월\n📌 렌즈의 수명을 늘리는 관리법\n🚀 바로 클릭', '', 1670000.00, 8350),
(12744, 1, '🎸 미니 일렉 기타 앰프 배터리형', '', '🎵 장소 불문! 야외에서도 연주 가능\n✨ 헤드폰 단자로 밤늦게도 조용하게\n⚡ 입문자용 가성비 끝판왕 모델\n▶ 확인하기', '', 1060000.00, 5300),
(12745, 1, '🎹 접이식 88건반 디지털 피아노', '', '✨ 공간은 적게, 감동은 크게! 폴딩 디자인\n🎯 실제 피아노와 유사한 터치감 구현\n🎁 전용 가방 및 페달 포함 기획전\n🚀 지금 구매', '', 450000.00, 2250),
(12746, 1, '🔦 고휘도 캠핑 랜턴 보조배터리 기능', '', '✨ 밤을 대낮처럼 밝히는 강력한 광량\n💎 스마트 기기 충전까지 가능한 멀티형\n📌 마그네틱 자석으로 철제 고정 가능\n▶ 구경하기', '', 1740000.00, 8700),
(12747, 1, '🕶️ 편광 선글라스 스포츠형 초경량', '', '🎧 눈부심은 차단하고 시야는 선명하게\n✨ 흘러내리지 않는 밀착형 디자인\n⚡ 라이딩, 골프 등 야외 활동 필수\n🚀 지금 확인', '', 1130000.00, 5650),
(12748, 1, '📱 스마트폰 가슴 마운트 홀더', '', '🎬 1인칭 시점의 역동적인 영상 촬영\n✨ 낚시, 자전거, 요리 브이로그 추천\n📌 전 기종 호환되는 조절식 밴드\n▶ 구매하기', '', 520000.00, 2600),
(12749, 1, '🧊 가정용 급속 제빙기 미니 사이즈', '', '💧 7분 만에 얼음이 톡톡! 카페 갈 필요 없어요\n✨ 자동 세척 기능으로 내부까지 깔끔\n📞 캠핑족들이 먼저 찾는 인기 모델\n🚀 상담 신청', '', 1810000.00, 9050),
(12750, 1, '🦾 손목 터널 증후군 보호대 마사지기', '', '💆 지친 손목을 위한 공기압과 온열 찜질\n💎 3단계 강도 조절로 나에게 맞게\n⚡ 사무직 필수 힐링 아이템\n▶ 혜택 보기', '', 1200000.00, 6000);
