INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12751, 1, '🎧 평면 자력형 헤드폰 전문가용', '', '🎵 왜곡 없는 순수한 사운드의 정점\n💎 넓은 공간감과 정밀한 해상도 구현\n⚡ 믹싱/마스터링 엔지니어 강력 추천\n▶ 제품 상세 보기', '', 590000.00, 2950),
(12752, 1, '💻 DDR5 고성능 RAM 64GB 패키지', '', '✨ 멀티태스킹의 한계를 넘어서는 속도\n🎯 영상 편집 및 3D 렌더링 최적화\n🔥 RGB 방열판으로 감성까지 충족\n🚀 지금 클릭', '', 1880000.00, 9400),
(12753, 1, '⌚ 스마트워치 티타늄 링크 브레이슬릿', '', '🎨 묵직한 존재감과 세련된 메탈릭 무드\n💎 흠집에 강한 프리미엄 소재 채택\n📌 한정 수량 입고 기념 할인 중\n▶ 구경하기', '', 1270000.00, 6350),
(12754, 1, '🖱️ 마그네틱 스위치 게이밍 마우스', '', '🎮 빛의 속도로 반응하는 광학 센서\n✨ 더블 클릭 현상 없는 반영구적 수명\n⚡ 프로 레벨의 정밀한 에임 컨트롤\n▶ 확인하기', '', 660000.00, 3300),
(12755, 1, '🔋 질화갈륨(GaN) 140W 접지형 충전기', '', '⚡ 노트북 3대 동시 충전도 가뿐하게\n💎 찌릿한 누설 전류 방지 접지 설계\n📌 여행용 멀티 플러그 포함 구성\n🚀 바로 주문', '', 1950000.00, 9750),
(12756, 1, '📷 풀프레임 미러리스 시네마 렌즈', '', '🎬 압도적인 보케와 부드러운 초점 전환\n🎯 영상 제작자를 위한 최고의 광학 기술\n🎁 지금 구매 시 렌즈 케어 키트 증정\n▶ 상세 보기', '', 1340000.00, 6700),
(12757, 1, '📺 120인치 전동 노출 스크린', '', '🏟️ 거실을 영화관으로 만드는 대화면\n✨ 리모컨 하나로 간편한 업/다운 제어\n⚡ 빔프로젝터와 세트 구매 시 추가 할인\n🚀 지금 확인', '', 730000.00, 3650),
(12758, 1, '⌨️ 가스켓 마운트 기계식 키보드', '', '💎 쫀득한 타건감의 끝판왕 설계\n✨ 통울림 없는 완벽한 저소음 실현\n📌 핫스왑 지원으로 스위치 커스텀\n▶ 구매하기', '', 120000.00, 600),
(12759, 1, '📱 스마트폰 가변 ND 필터 카메라용', '', '✨ 낮에도 영화 같은 장노출 촬영 가능\n🎯 자석 방식으로 간편한 탈부착\n💸 모바일 사진가들의 필수 아이템\n🚀 바로 구매', '', 1410000.00, 7050),
(12760, 1, '🔈 진공관 블루투스 스피커 하이브리드', '', '🎵 따뜻한 아날로그 음색과 선명한 고음\n🎨 투명 커버 속 빛나는 진공관 감성\n⚡ 홈카페 분위기를 완성하는 사운드\n▶ 더 보기', '', 800000.00, 4000),
(12761, 1, '🎮 플라이트 시뮬레이터 조이스틱', '', '🔥 하늘을 나는 생생한 조종석 경험\n🎯 정밀한 스로틀과 다기능 버튼 배치\n📌 항공 게임 매니아 강력 추천 모델\n🚀 지금 클릭', '', 190000.00, 950),
(12762, 1, '🖥️ 듀얼 모니터 거치대 고중량 지원', '', '✨ 무거운 대형 모니터도 처짐 없이 고정\n💎 자유로운 상하좌우 높낮이 조절\n⚡ 데스크테리어의 완성, 깔끔한 선 정리\n▶ 확인하기', '', 1480000.00, 7400),
(12763, 1, '🖨️ A3 지원 대형 포토 프린터', '', '📑 공모전 제출용 고품질 인화 지원\n💸 10색 잉크로 구현하는 깊은 색감\n📌 전문가용 인화지 세트 사은품\n🚀 지금 구매', '', 870000.00, 4350),
(12764, 1, '🧥 스마트 자세 교정 체어 밴드', '', '✨ 앉아만 있어도 바른 자세 유지\n🎯 허리 통증 완화 및 근육 강화 도움\n📞 직장인/수험생 공동 구매 할인\n▶ 제품 보기', '', 260000.00, 1300),
(12765, 1, '🌬️ 냉풍기 제빙기 일체형 하이엔드', '', '💎 얼음을 직접 만들어 더 시원한 바람\n✨ 자동 먼지 필터 청소 기능 탑재\n💸 시즌 오프 파격가 선착순 판매\n🚀 지금 확인', '', 1550000.00, 7750),
(12766, 1, '🧹 침구 전용 UV 살균 청소기 무선', '', '🎯 분당 1만 회 진동 패드로 미세먼지 제거\n✨ 고온 열풍 건조로 뽀송한 침구 완성\n📌 알레르기 케어 필수 가전\n▶ 더 보기', '', 940000.00, 4700),
(12767, 1, '🧊 데스크톱 미니 냉장고 6L', '', '🎨 음료와 간식을 손닿는 거리에\n💎 화장품 신선 보관용으로도 인기\n⚡ 저전력 설계로 하루 종일 부담 없이\n🚀 구매하기', '', 330000.00, 1650),
(12768, 1, '💧 대용량 초음파 가습기 거실형', '', '✨ 풍부한 가습량으로 넓은 거실도 촉촉하게\n🎯 상부 급수로 물 보충이 간편한 구조\n📌 무드등 기능으로 야간 분위기 연출\n▶ 확인하기', '', 1620000.00, 8100),
(12769, 1, '🍳 스마트 인덕션 1구 휴대용', '', '🍗 테이블 위에서 바로 즐기는 요리\n💎 슬림한 디자인과 강력한 화력 조절\n🎁 전용 보관 가방 증정 이벤트\n🚀 지금 주문', '', 1010000.00, 5050),
(12770, 1, '☕ 휴대용 에스프레소 추출기 수동', '', '☕ 전기가 필요 없는 나만의 야외 카페\n✨ 캡슐과 원두 가루 모두 사용 가능\n⚡ 캠핑/등산 필수 아이템\n▶ 구경하기', '', 400000.00, 2000),
(12771, 1, '🏋️ 지능형 스마트 체중계 앱 연동', '', '📈 근육량, 기초대사량 등 18가지 분석\n✨ 다이어트 그래프 자동 생성\n📌 건강한 라이프스타일의 시작\n🚀 지금 구매', '', 1690000.00, 8450),
(12772, 1, '💇 두피 스케일링 전동 브러쉬', '', '✨ 손으로 못 닦는 노폐물까지 깔끔하게\n🎯 샴푸 시 시원한 마사지 효과\n⚡ 완전 방수 및 무선 충전 방식\n▶ 확인하기', '', 1080000.00, 5400),
(12773, 1, '💆 무선 종아리 마사지기 듀얼형', '', '🔋 가방에 쏙! 이동하면서 마사지하세요\n💎 강력한 공기압으로 부종 제거 도움\n📌 수험생 및 임산부 선물 추천\n🚀 지금 클릭', '', 470000.00, 2350),
(12774, 1, '📽️ 휴대용 스크린 일체형 프로젝터', '', '🎬 펴기만 하면 바로 영화관 시작\n✨ 배터리 내장으로 야외 야간 상영 가능\n🎁 한정 수량 전용 파우치 증정\n▶ 확인하기', '', 1760000.00, 8800),
(12775, 1, '👜 아이패드 프로 마그네틱 거치대', '', '🎨 공중에 떠 있는 듯한 플로팅 디자인\n💎 자유로운 각도 조절 및 가로세로 회전\n⚡ 드로잉 및 영상 시청 최적화\n🚀 바로 주문', '', 1150000.00, 5750),
(12776, 1, '📻 고음질 오디오 리시버 블루투스', '', '🎵 일반 오디오를 최신 무선 기기로 변신\n✨ 끊김 없는 고성능 안테나 탑재\n📌 고전 장비의 부활, 지금 느껴보세요\n▶ 구경하기', '', 540000.00, 2700),
(12777, 1, '📏 초음파 신장계 디지털 측정기', '', '🛠️ 벽에 서기만 하면 1초 만에 키 측정\n✨ 성장기 아이들의 기록 관리 앱 연동\n⚡ 인테리어 소품 같은 미니멀 디자인\n🚀 지금 확인', '', 1830000.00, 9150),
(12778, 1, '🏮 캠핑용 무드 가스 랜턴 감성형', '', '✨ 따뜻한 불멍 분위기를 텐트 속으로\n💎 정교한 화력 조절 밸브 장착\n📌 감성 캠핑족 필수 컬렉션\n▶ 구매하기', '', 1220000.00, 6100),
(12779, 1, '🎙️ 하이엔드 USB 마이크 스튜디오급', '', '🎧 별도 장비 없이 PC 연결 즉시 사용\n✨ 4가지 픽업 패턴으로 모든 상황 대응\n⚡ 깨끗한 목소리 전달의 기준\n🚀 지금 클릭', '', 610000.00, 3050),
(12780, 1, '🔌 스마트 홈 허브 통합 제어기', '', '⚡ 집안 모든 가전을 폰 하나로 연결\n💎 외출 시 자동 절전 모드 실행\n📌 보안 카메라와 연동하여 안전 강화\n▶ 더 보기', '', 1900000.00, 9500),
(12781, 1, '🚲 자전거용 레이더 후방 경보기', '', '⚡ 뒤에서 오는 차량을 미리 알려줍니다\n💎 라이딩 안전을 위한 혁신적 가젯\n📌 가민/스마트폰 연동 지원\n🚀 지금 확인', '', 1290000.00, 6450),
(12782, 1, '🛴 어린이 전동 스쿠터 3륜 모델', '', '✨ 넘어지지 않는 구조로 초보자도 안심\n🎯 화려한 불빛과 귀여운 멜로디 기능\n⚡ 조카 선물 1위 인기 상품\n▶ 바로 구매', '', 680000.00, 3400),
(12783, 1, '🌡️ 디지털 미트 온도계 요리용', '', '✨ 스테이크 굽기를 정확하게 마스터\n💎 스테인리스 침 투입 방식\n📌 공식 셰프들이 추천하는 장비\n🚀 지금 주문', '', 1970000.00, 9850),
(12784, 1, '🧊 목걸이형 에어컨 펠티어 냉각', '', '🌬️ 단순 바람이 아닌 실제 얼음 냉각\n✨ 목 뒤를 직접 시원하게 만드는 기술\n⚡ 한여름 야외 작업 필수품\n▶ 더 보기', '', 1360000.00, 6800),
(12785, 1, '🍞 와이드 오븐 토스터기 4구', '', '✨ 온 가족 아침 식사를 한 번에 조리\n💎 베이글 전용 모드 탑재\n📌 레트로 디자인으로 주방 완성\n🚀 지금 클릭', '', 750000.00, 3750),
(12786, 1, '💧 스마트 칫솔 살균 거치대 무선', '', '🦷 칫솔 5개 동시 살균 및 건조\n✨ 인체 감지 센서로 안전하게 작동\n⚡ 깔끔한 화장실 정돈의 필수템\n▶ 확인하기', '', 140000.00, 700),
(12787, 1, '🧔 프리미엄 바디 면도기 전용 키트', '', '✨ 부드러운 절삭력으로 자극 없이\n🎯 엉킴 방지 세라믹 날 채택\n📌 방수 기능으로 간편 세척\n🚀 바로 구매', '', 1430000.00, 7150),
(12788, 1, '🎵 수면용 노이즈 마스킹 이어버드', '', '🎧 층간 소음, 코골이 소리 차단\n✨ 귀가 편안한 초소형 실리콘 팁\n⚡ 숙면 유도 전용 음원 내장\n▶ 구경하기', '', 820000.00, 4100),
(12789, 1, '💼 카메라 숄더백 캔버스 빈티지', '', '✨ 카메라 같지 않은 일상적인 디자인\n💎 내부 충격 흡수 파티션 분리 가능\n📌 데일리 백으로도 손색없는 스타일\n🚀 지금 확인', '', 210000.00, 1050),
(12790, 1, '💾 고성능 USB 4.0 플래시 드라이브', '', '🚀 외장 SSD급 속도를 손가락 크기로\n✨ 대용량 파일도 몇 초 만에 전송\n⚡ 메탈 바디의 견고한 내구성\n▶ 구매하기', '', 1500000.00, 7500),
(12791, 1, '👔 스팀 다리미 핸디형 고출력', '', '✨ 바쁜 아침 30초 퀵 예열 시스템\n💎 실크부터 코트까지 모든 원단 케어\n📌 물 보충이 쉬운 일체형 탱크\n🚀 지금 주문', '', 890000.00, 4450),
(12792, 1, '🥣 가정용 진공 저온 수비드 머신', '', '✨ 셰프의 스테이크를 집에서 구현\n🎯 물 온도를 일정하게 유지하는 정밀 제어\n⚡ 신규 런칭 기념 수비드 컨테이너 증정\n▶ 더 보기', '', 280000.00, 1400),
(12793, 1, '🧴 창문 로봇 청소기 듀얼 스핀', '', '💎 손 닿기 힘든 외부 유리창도 반짝\n✨ 강력한 흡착력과 낙하 방지 안전 끈\n📌 아파트 거실 창 청소의 혁명\n🚀 바로 클릭', '', 1570000.00, 7850),
(12794, 1, '🎸 사운드 카드 오디오 인터페이스', '', '🎵 잡음 없는 깨끗한 보컬 녹음 지원\n✨ 홈레코딩 입문자를 위한 가성비 팩\n⚡ DAW 소프트웨어 번들 증정\n▶ 확인하기', '', 960000.00, 4800),
(12795, 1, '🎹 핸드롤 피아노 88건반 실리콘', '', '✨ 돌돌 말아 가방에 쏙! 어디서든 연주\n🎯 이어폰 연결로 층간 소음 걱정 제로\n🎁 전용 악보 스탠드 포함\n🚀 지금 구매', '', 350000.00, 1750),
(12796, 1, '🔦 고광량 헤드 랜턴 등산/낚시용', '', '✨ 시야를 넓게 밝히는 와이드 LED\n💎 장시간 착용에도 편안한 밴드 설계\n📌 충전식 대용량 배터리 내장\n▶ 구경하기', '', 1640000.00, 8200),
(12797, 1, '🕶️ 야간 운전용 편광 안경 노란색 렌즈', '', '🎧 눈부신 상향등 차단 및 시야 선명화\n✨ 빗길 주행 시 차선 식별 도움\n⚡ 안전 운전을 위한 필수 액세서리\n🚀 지금 확인', '', 1030000.00, 5150),
(12798, 1, '📱 스마트폰 가변 삼각대 문어발형', '', '🎬 나무, 기둥 어디든 고정하여 촬영\n✨ 독창적인 각도에서 인생샷 남기기\n📌 블루투스 리모컨 기본 구성\n▶ 구매하기', '', 420000.00, 2100),
(12799, 1, '🧊 가정용 급속 제빙기 살균 모델', '', '💧 6분마다 쏟아지는 깨끗한 얼음\n✨ 자동 세척 및 UV 살균 기능 강화\n📞 여름 캠핑 필수 아이템 선점하세요\n🚀 상담 신청', '', 1710000.00, 8550),
(12800, 1, '🦾 손 안마기 무선 지압 공기압', '', '💆 컴퓨터 작업 후 지친 손을 위한 휴식\n💎 온열 기능으로 손끝까지 따뜻하게\n⚡ 부모님 효도 선물 1위 상품\n▶ 혜택 보기', '', 1100000.00, 5500);
