INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12801, 1, '🎧 오픈형 레퍼런스 헤드폰', '', '🎵 왜곡 없는 플랫한 사운드로 원음을 정확하게\n💎 장시간 믹싱 작업에도 압박 없는 착용감\n⚡ 오디오 전문가들이 신뢰하는 해상도\n▶ 제품 상세 보기', '', 490000.00, 2450),
(12802, 1, '💻 PCIE 5.0 초고속 NVMe SSD 2TB', '', '🚀 기존 SSD보다 2배 더 빠른 전송 속도\n✨ 대용량 영상 편집과 게임 로딩을 순식간에\n🔥 전용 방열판으로 쓰로틀링 걱정 끝\n🚀 지금 클릭', '', 1780000.00, 8900),
(12803, 1, '⌚ 스마트워치 전용 마그네틱 루프', '', '🎨 무단계 조절로 내 손목에 딱 맞는 핏\n💎 통기성 좋은 메쉬 소재의 쾌적함\n📌 간편한 탈부착 방식과 세련된 디자인\n▶ 구경하기', '', 1170000.00, 5850),
(12804, 1, '🖱️ 수직형 버티컬 무선 마우스', '', '🤫 손목 비틀림을 방지하는 57도 인체공학 설계\n✨ 장시간 사무 업무 시 피로도 대폭 감소\n⚡ 무소음 클릭으로 조용한 업무 환경\n▶ 확인하기', '', 560000.00, 2800),
(12805, 1, '🔋 200W 초고속 보조배터리 25000mAh', '', '⚡ 노트북 2대를 동시에 풀스피드 충전\n💎 현재 상태를 보여주는 스마트 LCD 탑재\n📌 기내 반입 가능한 최대 용량 설계\n🚀 바로 주문', '', 1850000.00, 9250),
(12806, 1, '📷 가변 화각 줌 렌즈 (F2.8 고정)', '', '🎬 전 구간 밝은 조리개로 야간 촬영도 선명하게\n🎯 빠르고 정확한 리니어 모터 AF 시스템\n🎁 지금 구매 시 UV 필터 증정\n▶ 상세 보기', '', 1240000.00, 6200),
(12807, 1, '📺 4K UHD 화상회의용 웹캠', '', '🏟️ 오토 프레이밍으로 인물을 항상 중앙에\n✨ 노이즈 캔슬링 마이크 내장으로 선명한 전달\n⚡ 재택근무의 퀄리티를 높이는 필수템\n🚀 지금 확인', '', 630000.00, 3150),
(12808, 1, '⌨️ 무선 기계식 키보드 (황축)', '', '💎 가볍고 경쾌한 타건감의 리니어 스위치\n✨ 3모드 연결(BT/2.4G/유선) 완벽 지원\n📌 윈도우/맥 레이아웃 자유 전환\n▶ 구매하기', '', 1920000.00, 9600),
(12809, 1, '📱 스마트폰 쿨링 팬 자력 부착식', '', '✨ 고사양 게임 시 발열을 즉각적으로 냉각\n🎯 펠티어 소자로 영하까지 내려가는 온도\n💸 프레임 드랍 없는 쾌적한 게임 플레이\n🚀 바로 구매', '', 1310000.00, 6550),
(12810, 1, '🔈 액티브 북쉘프 스피커 (aptX 지원)', '', '🎵 블루투스에서도 CD급 고음질을 경험하세요\n🎨 모던한 블랙 하이그로시 마감 디자인\n⚡ 별도 앰프가 필요 없는 올인원 사운드\n▶ 더 보기', '', 700000.00, 3500),
(12811, 1, '🎮 모바일 게이밍 컨트롤러 텔레스코픽', '', '🔥 스마트폰을 휴대용 콘솔처럼 변신\n🎯 홀 효과 센서로 스틱 쏠림 현상 방지\n📌 최신 에뮬레이터 및 게임 앱 호환\n🚀 지금 클릭', '', 1990000.00, 9950),
(12812, 1, '🖥️ 144Hz 휴대용 게이밍 모니터', '', '✨ 야외에서도 즐기는 고주사율의 부드러움\n💎 닌텐도 스위치/PS5 연결 즉시 사용\n⚡ 초슬림 베젤과 경량화로 뛰어난 휴대성\n▶ 확인하기', '', 1380000.00, 6900),
(12813, 1, '🖨️ 열전사 방식 무선 라벨기', '', '📑 이름표부터 바코드까지 폰으로 1초 출력\n💸 잉크 리필 필요 없는 경제적인 사용\n📌 전용 라벨지 5롤 포함 패키지\n🚀 지금 구매', '', 770000.00, 3850),
(12814, 1, '🧥 스마트 자세 모니터링 센서', '', '✨ 어깨가 굽으면 진동으로 즉시 알림\n🎯 전용 앱을 통한 일간/주간 자세 분석\n📞 거북목 예방을 위한 스마트한 선택\n▶ 제품 보기', '', 160000.00, 800),
(12815, 1, '🌬️ 탁상용 무선 에어 서큘레이터', '', '💎 작지만 강력한 직진성 바람으로 공기 순환\n✨ 120도 자동 회전 및 타이머 기능\n💸 사무실 개인용 냉방 아이템 추천\n🚀 지금 확인', '', 1450000.00, 7250),
(12816, 1, '🧹 차량용 무선 청소기 15000Pa', '', '🎯 자동차 시트 구석 먼지까지 빨아들이는 흡입력\n✨ 한 손에 쏙 들어오는 콤팩트한 사이즈\n📌 미세먼지 차단 이중 헤파필터 적용\n▶ 더 보기', '', 840000.00, 4200),
(12817, 1, '🧊 화장품 보관 전용 미니 쇼케이스', '', '🎨 성분을 지켜주는 일정한 온도 관리\n💎 내부 LED 조명으로 고급스러운 연출\n⚡ 무진동 설계로 소음 걱정 없는 침실 배치\n🚀 구매하기', '', 230000.00, 1150),
(12818, 1, '💧 스마트 IoT 초음파 가습기 4L', '', '✨ 외출해서도 앱으로 미리 켜두는 쾌적함\n🎯 시간당 300ml의 풍부한 미세 가습\n📌 통세척 가능한 위생적인 구조\n▶ 확인하기', '', 1520000.00, 7600),
(12819, 1, '🍳 다용도 멀티 쿠커 3in1', '', '🍗 찜, 국, 구이를 기기 하나로 끝내세요\n💎 논스틱 코팅으로 세척이 매우 간편함\n🎁 레시피 북 증정 프로모션 진행 중\n🚀 지금 주문', '', 910000.00, 4550),
(12820, 1, '☕ 전자동 원두 그라인더 15단계 조절', '', '☕ 브루잉부터 에스프레소까지 정밀 분쇄\n✨ 코니컬 버 채택으로 원두 풍미 보존\n⚡ 버튼 하나로 정량 분쇄 자동 멈춤\n▶ 구경하기', '', 300000.00, 1500),
(12821, 1, '🏋️ 스마트 줄넘기 LED 카운팅', '', '📈 공중에서 보이는 실시간 점프 횟수\n✨ 앱 연동으로 칼로리 소모량 자동 기록\n📌 유무선 겸용으로 실내에서도 가능\n🚀 지금 구매', '', 1590000.00, 7950),
(12822, 1, '💇 전동 두피 마사지기 방수 지원', '', '✨ 4개의 실리콘 헤드로 손맛 그대로\n🎯 건식/습식 모두 가능한 힐링 가전\n⚡ 부모님 명절 선물로 강력 추천\n▶ 확인하기', '', 980000.00, 4900),
(12823, 1, '💆 무선 온열 무릎 마사지기', '', '🔋 시린 무릎을 따뜻하게 감싸는 공기압\n💎 3단계 온도 조절과 진동 마사지\n📌 일상생활 중에도 착용 가능한 무선형\n🚀 지금 클릭', '', 370000.00, 1850),
(12824, 1, '📽️ 시네마틱 레이저 프로젝터 3000안시', '', '🎬 낮에도 TV처럼 선명한 압도적 광량\n✨ 자동 장애물 회피 및 스크린 맞춤\n🎁 전용 하이엔드 스피커 사은품\n▶ 확인하기', '', 1660000.00, 8300),
(12825, 1, '👜 맥북용 가죽 스탠드 슬리브', '', '🎨 파우치가 거치대로 변신하는 아이디어\n💎 타이핑이 편한 최적의 15도 각도\n⚡ 고급 인조가죽 소재의 내구성\n🚀 바로 주문', '', 1050000.00, 5250),
(12826, 1, '📻 레트로 카세트 플레이어 블루투스 겸용', '', '🎵 추억의 테이프를 무선 헤드폰으로 감상\n✨ 빈티지 감성과 현대적 편의성의 조화\n📌 인테리어 오브제로도 훌륭한 디자인\n▶ 구경하기', '', 440000.00, 2200),
(12827, 1, '📏 디지털 수평계 레이저 레벨기', '', '🛠️ 수직, 수평, 사선까지 한 번에 가이드\n✨ 가구 조립부터 액자 걸기까지 완벽하게\n⚡ 자석 베이스로 철제 기둥에 고정 가능\n🚀 지금 확인', '', 1730000.00, 8650),
(12828, 1, ' Lantern LED 캠핑 등기구 3색 조절', '', '✨ 전구색부터 주광색까지 무드에 맞게\n💎 대용량 배터리로 최대 100시간 사용\n📌 IPX5 방수로 갑작스러운 비에도 안심\n▶ 구매하기', '', 1120000.00, 5600),
(12829, 1, '🎙️ XLR 다이나믹 마이크 방송용', '', '🎧 주변 소음은 줄이고 목소리만 묵직하게\n✨ 팟캐스트, 스트리밍 전문가의 선택\n⚡ 금도금 커넥터로 신호 손실 최소화\n🚀 지금 클릭', '', 510000.00, 2550),
(12830, 1, '🔌 스마트 전력 측정 멀티탭', '', '⚡ 실시간 전기 사용량과 요금 확인\n💎 대기 전력 자동 차단으로 전기료 절약\n📌 앱을 통한 개별 소켓 제어 가능\n▶ 더 보기', '', 1800000.00, 9000),
(12831, 1, '🚲 자전거용 스마트 헬멧 LED 방향지시등', '', '⚡ 리모컨으로 조절하는 안전한 차선 변경\n💎 블루투스 스피커와 마이크 내장\n📌 사고 감지 시 비상 연락 알림 기능\n🚀 지금 확인', '', 1190000.00, 5950),
(12832, 1, '🛴 오프로드 전동 킥보드 10인치 타이어', '', '✨ 비포장도로도 안정적인 서스펜션 탑재\n🎯 강력한 듀얼 모터의 등판 퍼포먼스\n⚡ 장거리 주행을 위한 고용량 배터리\n▶ 바로 구매', '', 580000.00, 2900),
(12833, 1, '🌡️ 고정밀 디지털 실내외 온도계', '', '✨ 거실과 실외 온도를 한눈에 확인\n💎 습도 및 불쾌지수 표시 기능 포함\n📌 미니멀한 디자인으로 어디든 조화\n🚀 지금 주문', '', 1870000.00, 9350),
(12834, 1, '🧊 미니 무선 냉풍기 나노 분사형', '', '🌬️ 물 분자로 주변 온도를 빠르게 다운\n✨ 7색 무드등으로 야간 취침등 활용\n⚡ 캠핑장 나만의 쿨러로 강력 추천\n▶ 더 보기', '', 1260000.00, 6300),
(12835, 1, '🍞 고성능 푸드 프로세서 2L', '', '✨ 다지기, 반죽, 슬라이스를 순식간에\n💎 스테인리스 S자 칼날과 5종 액세서리\n📌 요리 시간을 반으로 줄여주는 장비\n🚀 지금 클릭', '', 650000.00, 3250),
(12836, 1, '💧 전동 실리콘 안면 클렌징 브러쉬', '', '🦷 미세 진동으로 모공 속 노폐물 제거\n✨ 피부 타입별 15단계 강도 조절\n⚡ 반영구적 실리콘으로 위생적인 사용\n▶ 확인하기', '', 1940000.00, 9700),
(12837, 1, '🧔 코털 제거기 진동 저소음 모델', '', '✨ 보이지 않는 곳까지 깔끔한 매너\n🎯 피부 자극 없는 듀얼 엣지 칼날\n📌 물세척 가능한 헤드로 관리 간편\n🚀 바로 구매', '', 1330000.00, 6650),
(12838, 1, '🎵 명상 전용 싱잉볼 블루투스 스피커', '', '🎧 마음을 차분하게 하는 힐링 주파수\n✨ 실제 싱잉볼 소리를 고음질로 재현\n⚡ 스트레스 완화 및 명상 가이드 앱 포함\n▶ 구경하기', '', 720000.00, 3600),
(12839, 1, '💼 슬림 비즈니스 가죽 브리프케이스', '', '✨ 전문적인 인상을 주는 모던 디자인\n💎 14인치 노트북과 서류 완벽 수납\n📌 스크래치에 강한 사피아노 가죽\n🚀 지금 확인', '', 110000.00, 550),
(12840, 1, '💾 마이크로 SD카드 V30 512GB', '', '🚀 4K 영상 촬영에 최적화된 고속 쓰기\n✨ 블랙박스, 액션캠용 고내구성 모델\n⚡ 데이터 복구 소프트웨어 라이선스 포함\n▶ 구매하기', '', 1400000.00, 7000),
(12841, 1, '👔 초미세 건식 다리미 세라믹 코팅', '', '✨ 단추 사이사이까지 정교한 다림질\n💎 옷감 손상 방지 자동 온도 조절\n📌 가벼운 무게로 손목 부담 제로\n🚀 지금 주문', '', 790000.00, 3950),
(12842, 1, '🥣 수비드 전용 진공 롤 50매 세트', '', '✨ 끓는 물에서도 안전한 BPA FREE\n🎯 뛰어난 밀착력으로 육즙 완벽 보존\n⚡ 모든 브랜드 진공 포장기 호환\n▶ 더 보기', '', 180000.00, 900),
(12843, 1, '🧴 초음파 쥬얼리 세척기 가정용', '', '💎 빛바랜 반지와 목걸이를 새것처럼\n✨ 미세 버블이 틈새 때를 완벽 제거\n📌 안경과 메이크업 도구 세척 가능\n🚀 바로 클릭', '', 1470000.00, 7350),
(12844, 1, '🎸 사일런트 바이올린 연습용 패키지', '', '🎵 헤드폰 연결로 층간 소음 걱정 끝\n✨ 실제 바이올린과 동일한 운지감 구현\n⚡ 앰프 연결로 화려한 공연도 가능\n▶ 확인하기', '', 860000.00, 4300),
(12845, 1, '🎹 휴대용 롤업 드럼 패드 9패드', '', '✨ 돌돌 말아 어디서든 드럼 연습\n🎯 내장 스피커와 헤드폰 단자 탑재\n🎁 전용 드럼 스틱 및 페달 증정\n🚀 지금 구매', '', 250000.00, 1250),
(12846, 1, '🔦 전력 표시 고휘도 손전등 2000m', '', '✨ 2km 밖까지 비추는 강력한 직진성\n💎 알루미늄 합금 바디의 극한 내구성\n📌 보조배터리 출력 및 방수 지원\n▶ 구경하기', '', 1540000.00, 7700),
(12847, 1, '🕶️ 오디오 선글라스 편광 골전도', '', '🎧 음악을 들으며 주변 소리도 놓치지 마세요\n✨ 자외선 차단과 통화 기능을 안경 하나로\n⚡ 라이딩과 러닝 시 안전한 음악 감상\n🚀 지금 확인', '', 930000.00, 4650),
(12848, 1, '📱 스마트폰 차량용 맥세이프 거치대', '', '🎬 흔들림 없는 강력한 자력 고정\n✨ 무선 충전과 거치를 동시에 해결\n📌 대시보드 및 송풍구 겸용 마운트\n▶ 구매하기', '', 320000.00, 1600),
(12849, 1, '🧊 가정용 급속 파쇄 제빙기 (빙수용)', '', '💧 단단한 얼음부터 눈꽃 얼음까지\n✨ 버튼 하나로 빙수 얼음 자동 생산\n📞 홈카페 여름 메뉴 필수 준비물\n🚀 상담 신청', '', 1610000.00, 8050),
(12850, 1, '🦾 손가락 관절 전용 마사지기', '', '💆 마디마디 시원하게 주무르는 공기압\n💎 손이 자주 붓는 분들을 위한 맞춤 케어\n⚡ 무선형으로 언제 어디서나 편리하게\n▶ 혜택 보기', '', 1000000.00, 5000);
