INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12851, 1, '🎧 평면 자력형 오픈형 헤드폰', '', '🎵 왜곡 없는 원음 그대로의 감동을 전달\n💎 장시간 감상에도 편안한 대형 이어패드\n⚡ 하이파이 오디오 입문자 추천 모델\n▶ 제품 상세 보기', '', 390000.00, 1950),
(12852, 1, '💻 지능형 수랭 쿨러 3열 라디에이터', '', '✨ CPU 온도를 실시간 표시하는 LCD 탑재\n🎯 극저소음 펌프로 정숙한 작업 환경\n🔥 고사양 게이밍 PC의 필수 완성템\n🚀 지금 클릭', '', 1680000.00, 8400),
(12853, 1, '⌚ 스마트워치 밀레니즈 루프 스트랩', '', '🎨 스테인리스 메쉬로 완성하는 모던 룩\n💎 자석 방식으로 자유로운 길이 조절\n📌 전 기종 호환 가능 및 6색 라인업\n▶ 구경하기', '', 1070000.00, 5350),
(12854, 1, '🖱️ 경량 게이밍 마우스 (무게 50g)', '', '🎮 손목 부담 제로! 깃털 같은 가벼움\n✨ 고성능 26K 정밀 센서 탑재\n⚡ 승률을 높이는 초고속 반응 속도\n▶ 확인하기', '', 460000.00, 2300),
(12855, 1, '🔋 140W 초고속 충전 지원 파워뱅크', '', '⚡ 노트북 충전도 거뜬한 고출력 설계\n💎 컴팩트한 사이즈로 뛰어난 휴대성\n📌 디지털 잔량 표시 및 3포트 구성\n🚀 바로 주문', '', 1750000.00, 8750),
(12856, 1, '📷 미러리스 전용 망원 줌 렌즈', '', '🎬 멀리 있는 피사체도 선명하게 포착\n🎯 강력한 광학식 손떨림 보정 내장\n🎁 구매 시 렌즈 보호 필터 증정\n▶ 상세 보기', '', 1140000.00, 5700),
(12857, 1, '📺 스마트 사이니지용 대형 모니터', '', '🏟️ 24시간 연속 가동에도 안정적인 성능\n✨ 선명한 밝기로 매장 홍보 효과 극대화\n⚡ 비즈니스 솔루션 무료 컨설팅\n🚀 상담 신청하기', '', 530000.00, 2650),
(12858, 1, '⌨️ 무선 기계식 키보드 (은축)', '', '💎 찰나의 순간을 잡는 짧은 입력 지점\n✨ 유무선 3모드 연결로 뛰어난 호환성\n📌 RGB 백라이트 커스터마이징 가능\n▶ 구매하기', '', 1820000.00, 9100),
(12859, 1, '📱 스마트폰 가죽 맥세이프 케이스', '', '✨ 고급 천연 가죽의 부드러운 그립감\n🎯 강력한 자력으로 액세서리 완벽 호환\n💸 한정 수량 특별 할인가 판매\n🚀 바로 구매', '', 1210000.00, 6050),
(12860, 1, '🔈 액티브 북쉘프 스피커 (우드 디자인)', '', '🎵 거실을 콘서트 홀로 만드는 풍부한 저음\n🎨 클래식한 감성을 더하는 리얼 우드 마감\n⚡ 입문용 하이파이 스피커의 기준\n▶ 더 보기', '', 600000.00, 3000),
(12861, 1, '🎮 아케이드 조이스틱 격투 게임용', '', '🔥 오락실의 손맛을 그대로 재현한 설계\n🎯 저지연 기술로 콤보 입력 완벽 지원\n📌 PC/콘솔 기기 즉시 연결 사용\n🚀 지금 클릭', '', 1890000.00, 9450),
(12862, 1, '🖥️ 듀얼 모니터 암 고중량 실린더', '', '✨ 대형 모니터도 처짐 없이 자유롭게 배치\n💎 데스크 공간을 200% 활용하는 비결\n⚡ 깔끔한 선 정리 클립 내장\n▶ 확인하기', '', 1280000.00, 6400),
(12863, 1, '🖨️ 스마트 라벨 프린터 (앱 전용)', '', '📑 정리 정돈의 시작! 폰으로 간편 출력\n💸 잉크가 필요 없는 경제적 유지비\n📌 전용 라벨지 3롤 무료 증정\n🚀 지금 구매', '', 670000.00, 3350),
(12864, 1, '🧥 스마트 자세 교정 벨트 (센서형)', '', '✨ 구부정한 자세를 진동 알림으로 교정\n🎯 전용 앱으로 일일 달성도 체크\n📞 사무직 및 학생 필수 추천템\n▶ 제품 보기', '', 1960000.00, 9800),
(12865, 1, '🌬️ 서큘레이터 겸용 무엽 선풍기', '', '💎 날개 없어 아이들에게도 안전한 바람\n✨ 강력한 공기 정화 필터 기능 포함\n💸 시즌 오프 한정 할인 혜택\n🚀 지금 확인', '', 1350000.00, 6750),
(12866, 1, '🧹 핸디형 무선 청소기 (차량용 겸용)', '', '🎯 작지만 강력한 15000Pa 흡입력\n✨ 틈새 노즐로 구석구석 깨끗하게\n📌 고성능 BLDC 모터 탑재 모델\n▶ 더 보기', '', 740000.00, 3700),
(12867, 1, '🧊 미니 화장품 냉장고 (저소음 설계)', '', '🎨 화장품 신선도를 유지하는 최적 온도\n💎 세련된 디자인으로 침실 인테리어 완성\n⚡ 무진동 방식으로 밤에도 조용하게\n🚀 구매하기', '', 130000.00, 650),
(12868, 1, '💧 대용량 초음파 가습기 5L', '', '✨ 상부 급수로 간편하게 물 보충\n🎯 풍부한 미스트로 실내 습도 최적 유지\n📌 세척이 간편한 완전 분리 구조\n▶ 확인하기', '', 1420000.00, 7100),
(12869, 1, '🍳 인덕션용 멀티 그리들 팬', '', '🍗 캠핑과 가정에서 즐기는 만능 조리 도구\n💎 눌어붙지 않는 강력한 논스틱 코팅\n🎁 전용 보관 가방 증정 이벤트\n🚀 지금 주문', '', 810000.00, 4050),
(12870, 1, '☕ 전자동 에스프레소 머신 (원두용)', '', '☕ 집에서도 즐기는 바리스타의 커피\n✨ 버튼 하나로 그라인딩부터 추출까지\n⚡ 합리적인 가격의 홈카페 끝판왕\n▶ 구경하기', '', 200000.00, 1000),
(12871, 1, '🏋️ 스마트 웨어러블 자세 분석기', '', '📈 실시간 척추 각도 모니터링 기능\n✨ 옷 안에 착용해도 티 나지 않는 슬림함\n📌 거북목 예방을 위한 최적의 솔루션\n🚀 지금 구매', '', 1490000.00, 7450),
(12872, 1, '💇 전문가용 음이온 드라이기 2200W', '', '✨ 모발 손상을 줄여주는 지능형 온도 제어\n🎯 바쁜 아침 시간을 단축하는 강력 풍량\n⚡ 전문가용 집중 노즐 포함 구성\n▶ 제품 보기', '', 880000.00, 4400),
(12873, 1, '💆 무선 종아리 마사지기 (온열형)', '', '🔋 지친 다리를 시원하게 풀어주는 공기압\n💎 3단계 강도 조절과 따뜻한 찜질 효과\n📌 부모님 선물 만족도 1위 아이템\n🚀 지금 클릭', '', 270000.00, 1350),
(12874, 1, '📽️ 휴대용 미니 빔프로젝터 FHD', '', '🎬 캠핑장에서 즐기는 100인치 대화면\n✨ 넷플릭스, 유튜브 내장으로 단독 구동\n🎁 전용 삼각대 무료 증정 기획전\n▶ 확인하기', '', 1560000.00, 7800),
(12875, 1, '👜 맥북용 가죽 슬리브 파우치', '', '🎨 슬림하고 우아한 실루엣의 보호 케이스\n💎 부드러운 스웨이드 안감으로 기스 방지\n⚡ 세련된 4가지 어반 컬러 출시\n🚀 바로 주문', '', 950000.00, 4750),
(12876, 1, '📻 올인원 레트로 오디오 시스템', '', '🎵 LP, CD, 블루투스까지 모두 하나로\n✨ 거실의 품격을 높이는 앤티크 디자인\n📌 고출력 스피커 내장으로 생생한 음원\n▶ 구경하기', '', 340000.00, 1700),
(12877, 1, '📏 레이저 거리 측정기 (최대 40m)', '', '🛠️ 이사, 인테리어 시 필수 측정 도구\n✨ 버튼 한 번으로 면적, 부피 계산 끝\n⚡ 한 손에 쏙 들어오는 포켓 사이즈\n🚀 지금 확인', '', 1630000.00, 8150),
(12878, 1, '🏮 캠핑용 LED 랜턴 (보조배터리 겸용)', '', '✨ 밤을 대낮처럼 밝히는 강력한 광량\n💎 스마트폰 충전도 가능한 대용량 배터리\n📌 마그네틱 자석으로 철제 부착 가능\n▶ 구매하기', '', 1020000.00, 5100),
(12879, 1, '🎙️ 콘덴서 마이크 세트 (방송용)', '', '🎧 노이즈 없는 선명한 보컬 녹음\n✨ 팝필터와 데스크 스탠드 포함 풀세트\n⚡ 1인 미디어 크리에이터 입문 추천\n🚀 지금 클릭', '', 410000.00, 2050),
(12880, 1, '🔌 스마트 멀티탭 (앱 원격 제어)', '', '⚡ 밖에서도 가전 제품 전원을 끄고 켜세요\n💎 실시간 전력량 체크로 전기세 절약\n📌 개별 소켓 타이머 예약 기능 탑재\n▶ 더 보기', '', 1700000.00, 8500),
(12881, 1, '🚲 전기 자전거 (접이식 도심형)', '', '⚡ 출퇴근이 즐거워지는 가벼운 주행\n💎 한 번 충전으로 최대 60km 주행 가능\n📌 헬멧 및 자물쇠 증정 프로모션\n🚀 지금 확인', '', 1090000.00, 5450),
(12882, 1, '🛴 어린이용 전동 킥보드 (안전 모델)', '', '✨ 속도 제한 기능으로 안전한 놀이 가능\n🎯 화려한 LED 라이트와 튼튼한 발판\n⚡ 아이들이 가장 받고 싶은 선물\n▶ 바로 구매', '', 480000.00, 2400),
(12883, 1, '🌡️ 디지털 미트 온도계 (요리용)', '', '✨ 스테이크 굽기를 정확하게 맞추는 비결\n💎 신속하고 정확한 온도 감지 센서\n📌 초보 주부도 셰프처럼 요리 가능\n🚀 지금 주문', '', 1770000.00, 8850),
(12884, 1, '🧊 탁상용 미니 무선 냉풍기', '', '🌬️ 물과 얼음으로 시원한 개인 냉방\n✨ USB 충전식으로 야외에서도 사용 가능\n⚡ 여름 미리 준비 파격 할인 진행 중\n▶ 더 보기', '', 1160000.00, 5800),
(12885, 1, '🍞 샌드위치 & 와플 메이커 2in1', '', '✨ 5분 만에 완성하는 든든한 아침 식사\n💎 분리형 플레이트로 간편한 세척\n📌 홈브런치 카페 분위기 연출\n🚀 지금 클릭', '', 550000.00, 2750),
(12886, 1, '💧 음파 전동 칫솔 (미백 모드 탑재)', '', '🦷 분당 4만 번의 진동으로 완벽한 세정\n✨ 잇몸 손상 없이 부드러운 케어 가능\n⚡ 휴대용 충전 케이스 포함 패키지\n▶ 확인하기', '', 1840000.00, 9200),
(12887, 1, '🧔 바디 트리머 (남성용 그루밍)', '', '✨ 겨드랑이, 다리 털을 자극 없이 정리\n🎯 방수 기능으로 샤워 중에도 사용 가능\n📌 깔끔한 인상을 위한 필수 아이템\n🚀 바로 구매', '', 1230000.00, 6150),
(12888, 1, '🎵 화이트 노이즈 머신 (수면 유도)', '', '🎧 깊은 잠을 방해하는 소음을 차단\n✨ 30가지 자연의 소리와 편안한 무드등\n⚡ 불면증 완화 및 집중력 향상 도움\n▶ 구경하기', '', 620000.00, 3100),
(12889, 1, '💼 카메라 백팩 (파티션 분리형)', '', '✨ 렌즈와 바디를 안전하게 수납\n💎 일상 백팩으로도 활용 가능한 디자인\n📌 방수 커버 포함으로 전천후 사용\n🚀 지금 확인', '', 1910000.00, 9550),
(12890, 1, '💾 고성능 외장 SSD 1TB (초소형)', '', '🚀 8K 영상도 끊김 없이 전송하는 속도\n✨ 충격에 강한 메탈 바디와 컴팩트 사이즈\n⚡ 소중한 데이터를 가장 안전하게 보관\n▶ 구매하기', '', 1300000.00, 6500),
(12891, 1, '👔 핸디형 보풀 제거기 (충전식)', '', '✨ 옷감을 상하지 않게 보풀만 쏙 제거\n💎 강력한 6중 칼날과 넓은 흡입구\n📌 헌 옷을 새 옷처럼 만드는 마법\n🚀 지금 주문', '', 690000.00, 3450),
(12892, 1, '🥣 수비드 머신 (전문가용 사양)', '', '✨ 집에서도 레스토랑 스테이크 구현\n🎯 0.1도 단위의 정밀한 온도 조절\n⚡ 건강한 저칼로리 식단의 필수품\n▶ 더 보기', '', 1980000.00, 9900),
(12893, 1, '🧴 전동 창문 청소기 (로봇형)', '', '💎 위험한 외부 창문 청소는 로봇에게\n✨ 강력한 흡착력으로 낙하 걱정 제로\n📌 아파트 거실 창 필수 관리 아이템\n🚀 바로 클릭', '', 1370000.00, 6850),
(12894, 1, '🎸 포터블 기타 앰프 (블루투스 겸용)', '', '🎵 연습용 앰프와 음악 스피커를 동시에\n✨ 내장 배터리로 장소 불문 연주 가능\n⚡ 일렉/어쿠스틱 기타 완벽 호환\n▶ 확인하기', '', 760000.00, 3800),
(12895, 1, '🎹 접이식 88건반 디지털 피아노', '', '✨ 공간 활용 만점! 반으로 접어 보관 가능\n🎯 실제 피아노의 타건감을 그대로 구현\n🎁 전용 가방 및 페달 포함 구성\n🚀 지금 구매', '', 150000.00, 750),
(12896, 1, '🔦 충전식 고휘도 헤드 랜턴', '', '✨ 야간 등산 및 낚시 시 밝은 시야 확보\n💎 각도 조절 및 센서 제어 기능 탑재\n📌 장시간 착용에도 가벼운 무게\n▶ 구경하기', '', 1440000.00, 7200),
(12897, 1, '🕶️ 오디오 스마트 안경 (블루투스)', '', '🎧 음악 감상과 통화를 안경 하나로\n✨ 귀를 가리지 않아 주변 소리도 안전하게\n⚡ 스타일과 기능을 모두 잡은 혁신 아이템\n🚀 지금 확인', '', 830000.00, 4150),
(12898, 1, '📱 스마트폰 삼각대 (블루투스 리모컨)', '', '🎬 흔들림 없는 브이로그 및 단체 사진\n✨ 가볍고 튼튼한 알루미늄 소재\n📌 여행 필수품! 지금 바로 준비하세요\n▶ 구매하기', '', 220000.00, 1100),
(12899, 1, '🧊 가정용 제빙기 (급속 생산)', '', '💧 7분마다 쏟아지는 깨끗한 얼음\n✨ 자동 세척 기능으로 내부까지 위생적\n📞 얼음 정수기보다 경제적인 선택\n🚀 상담 신청', '', 1510000.00, 7550),
(12900, 1, '🦾 목/어깨 무선 마사지기 (주무름)', '', '💆 전문가의 손길처럼 시원한 압력\n💎 온열 기능으로 근육 이완 효과 극대화\n⚡ 명절 부모님 효도 선물 강력 추천\n▶ 혜택 보기', '', 900000.00, 4500);
