INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12901, 1, '🎧 평면 자력형 유선 헤드폰', '', '🎵 일반 드라이버와 차원이 다른 초고해상도 사운드\n💎 오픈형 설계로 느끼는 압도적인 공간감\n⚡ 오디오 매니아를 위한 하이엔드 입문기\n▶ 제품 상세 보기', '', 290000.00, 1450),
(12902, 1, '💻 DDR5 6400MHz 고성능 RAM 32GB', '', '🚀 차세대 규격으로 즐기는 극한의 오버클러킹\n✨ RGB 조명으로 화려한 본체 튜닝 효과\n🔥 대용량 작업과 게임을 동시에 쾌적하게\n🚀 지금 클릭', '', 1580000.00, 7900),
(12903, 1, '⌚ 스마트워치 티타늄 링크 브레이슬릿', '', '🎨 가벼움과 강인함을 동시에 잡은 프리미엄 소재\n💎 원터치 버클로 간편한 착용과 탈착\n📌 비즈니스 수트에 완벽하게 어울리는 디자인\n▶ 구경하기', '', 970000.00, 4850),
(12904, 1, '🖱️ 무선 트랙볼 마우스 (인체공학)', '', '🤫 팔을 움직이지 않아 좁은 공간에서도 최적\n✨ 엄지손가락 제어로 손목 통증 완화\n⚡ 장시간 문서 작업이 잦은 분들께 추천\n▶ 확인하기', '', 360000.00, 1800),
(12905, 1, '🔋 100W 질화갈륨(GaN) 4포트 충전기', '', '⚡ 노트북부터 폰까지 어댑터 하나로 해결\n💎 초소형 사이즈로 여행 시 짐을 획기적으로 축소\n📌 과전압 방지 안전 설계 적용\n🚀 바로 주문', '', 1650000.00, 8250),
(12906, 1, '📷 시네마틱 광각 단렌즈 (F1.8)', '', '🎬 브이로그 촬영에 최적화된 넓은 화각\n🎯 배경 흐림 효과로 인물을 더욱 돋보이게\n🎁 렌즈 후드 및 전용 파우치 증정\n▶ 상세 보기', '', 1040000.00, 5200),
(12907, 1, '📺 34인치 울트라와이드 커브드 모니터', '', '🏟️ 21:9 비율로 영화 같은 몰입감 선사\n✨ 한 화면에 여러 창을 띄우는 멀티태스킹의 혁신\n⚡ 144Hz 주사율로 부드러운 화면 전환\n🚀 지금 확인', '', 430000.00, 2150),
(12908, 1, '⌨️ 60% 미니 기계식 키보드 (적축)', '', '💎 데스크 공간을 넓게 쓰는 컴팩트 레이아웃\n✨ 소음이 적고 부드러운 리니어 타건감\n📌 게이머를 위한 무한 동시 입력 지원\n▶ 구매하기', '', 1720000.00, 8600),
(12909, 1, '📱 스마트폰 가죽 지갑 케이스 (맥세이프)', '', '✨ 카드 수납과 거치대 기능을 한 번에\n🎯 강력한 자석으로 케이스 위에 착 붙는 편리함\n💸 고급 소가죽 소재의 클래식한 감성\n🚀 바로 구매', '', 1110000.00, 5550),
(12910, 1, '🔈 블루투스 진공관 스피커 (하이브리드)', '', '🎵 아날로그의 따뜻한 음색과 디지털의 편리함\n🎨 인테리어 분위기를 살리는 진공관 조명\n⚡ 카페나 거실용 스피커로 강력 추천\n▶ 더 보기', '', 500000.00, 2500),
(12911, 1, '🎮 비행 시뮬레이션 조이스틱 세트', '', '🔥 실제 조종석에 앉은 듯한 리얼한 조작감\n🎯 정밀한 스로틀 제어로 비행의 재미 극대화\n📌 최신 비행 시뮬레이터 게임 완벽 호환\n🚀 지금 클릭', '', 1790000.00, 8950),
(12912, 1, '🖥️ 무선 스크린바 모니터 조명', '', '✨ 모니터 반사를 방지하고 눈의 피로를 감소\n💎 밝기와 색온도를 무선 다이얼로 조절\n⚡ 데스크테리어의 완성, 세련된 블랙 디자인\n▶ 확인하기', '', 1180000.00, 5900),
(12913, 1, '🖨️ 휴대용 포토 프린터 (인화지 타입)', ' ', '📑 스마트폰 속 추억을 10초 만에 인화하세요\n💸 다이어리 꾸미기에 딱 맞는 신용카드 사이즈\n📌 전용 인화지 20매 포함 특가 패키지\n🚀 지금 구매', '', 570000.00, 2850),
(12914, 1, '🧥 전동 높이 조절 모션 데스크', '', '✨ 버튼 하나로 앉았다 서기 자유롭게\n🎯 허리 건강을 지키는 가장 쉬운 방법\n📞 튼튼한 듀얼 모터로 흔들림 없는 고정\n▶ 제품 보기', '', 1860000.00, 9300),
(12915, 1, '🌬️ 이동식 냉매 에어컨 (창문형 키트)', '', '💎 실외기 설치가 불필요한 간편한 냉방\n✨ 제습 기능 포함으로 쾌적한 여름 준비\n💸 원룸 및 공부방 전용 냉방기 추천\n🚀 지금 확인', '', 1250000.00, 6250),
(12916, 1, '🧹 차량용 공기청정기 (H13 헤파필터)', '', '🎯 미세먼지와 담배 냄새를 99% 제거\n✨ 컵홀더에 쏙 들어가는 원통형 디자인\n📌 USB 전원으로 시동 시 자동 작동\n▶ 더 보기', '', 640000.00, 3200),
(12917, 1, '🧊 스마트 와인 셀러 (8구용)', '', '🎨 와인의 풍미를 지켜주는 항온·항습 기능\n💎 자외선 차단 글라스로 신선도 보존\n⚡ 집에서도 즐기는 프리미엄 와인 홈바\n🚀 구매하기', '', 1930000.00, 9650),
(12918, 1, '💧 스마트 온수 매트 (앱 제어형)', '', '✨ 전자파 걱정 없는 포근한 숙면\n🎯 좌우 개별 온도 조절로 부부 맞춤 케어\n📌 저소음 모터로 밤새 조용하게 유지\n▶ 확인하기', '', 1320000.00, 6600),
(12919, 1, '🍳 와이드 전기 그릴 (기름 빠짐 구조)', '', '🍗 온 가족이 함께 즐기는 대용량 구이 요리\n💎 연기 발생을 최소화한 팬 설계\n🎁 전용 보관 가방 증정 이벤트 중\n🚀 지금 주문', '', 710000.00, 3550),
(12920, 1, '☕ 홈카페 콜드브루 메이커 (점적식)', '', '☕ 한 방울씩 정성스럽게 내리는 진한 풍미\n✨ 위생적인 유리 소재와 정밀 조절 밸브\n⚡ 여름철 아이스 커피를 위한 최고의 선택\n▶ 구경하기', '', 100000.00, 500),
(12921, 1, '🏋️ 가정용 접이식 워킹패드 (저소음)', '', '📈 층간 소음 걱정 없는 특수 충격 흡수 패드\n✨ 사용 후 반으로 접어 침대 밑 보관 가능\n📌 스마트폰 앱으로 주간 운동량 기록\n🚀 지금 구매', '', 1390000.00, 6950),
(12922, 1, '💇 휴대용 무선 미니 고데기', '', '✨ 여행지나 출근길 가방 속에 쏙!\n🎯 3단계 온도 조절과 빠른 예열 시간\n⚡ C타입 충전으로 언제 어디서나 스타일링\n▶ 확인하기', '', 780000.00, 3900),
(12923, 1, '💆 저주파 마사지기 (패드 부착식)', '', '🔋 뭉친 근육을 부드럽게 풀어주는 EMS 기술\n💎 다양한 부위에 밀착되는 젤 패드 4장 구성\n📌 주머니에 넣고 다니는 전신 관리사\n🚀 지금 클릭', '', 170000.00, 850),
(12924, 1, '📽️ 4K 초단초점 프로젝터 (거실용)', '', '🎬 벽 앞 10cm에서 구현하는 120인치 화면\n✨ 낮에도 선명한 압도적인 명암비\n🎁 전용 ALR 스크린 증정 특별 패키지\n▶ 확인하기', '', 1460000.00, 7300),
(12925, 1, '👜 아이패드 전용 매직 키보드 케이스', '', '🎨 태블릿을 노트북처럼 활용하는 트랙패드\n💎 자력으로 부착되는 플로팅 캔틸레버 디자인\n⚡ 패스스루 충전 포트 내장\n🚀 바로 주문', '', 850000.00, 4250),
(12926, 1, '📻 빈티지 포터블 라디오 (원목 마감)', '', '🎵 따뜻한 아날로그 감성의 FM/AM 수신\n✨ 인테리어 소품으로도 가치 있는 디자인\n📌 내장 배터리로 야외 캠핑 시 유용\n▶ 구경하기', '', 240000.00, 1200),
(12927, 1, '📏 스마트 레이저 수평계 (360도 회전)', '', '🛠️ 실내 인테리어 및 셀프 시공 필수 장비\n✨ 상하좌우 모든 방향으로 정밀 라인 생성\n⚡ 자석 베이스로 금속에 단단히 고정\n🚀 지금 확인', '', 1530000.00, 7650),
(12928, 1, '🏮 캠핑용 감성 가스 랜턴 (심지 타입)', '', '✨ 밤을 분위기 있게 밝히는 따뜻한 불꽃\n💎 세밀한 화력 조절로 무드 연출 가능\n📌 전용 하드 케이스로 안전한 이동\n▶ 구매하기', '', 920000.00, 4600),
(12929, 1, '🎙️ 팟캐스트용 오디오 인터페이스', '', '🎧 고음질 마이크와 헤드폰을 하나로 연결\n✨ 직관적인 버튼으로 실시간 음향 조절\n⚡ 초보 크리에이터도 손쉽게 세팅 가능\n🚀 지금 클릭', '', 310000.00, 1550),
(12930, 1, '🔌 사물인터넷(IoT) 스마트 플러그', '', '⚡ 외출 중에도 전등이나 가습기를 제어하세요\n💎 전력 과부하 시 알림 및 자동 차단 기능\n📌 구글 홈/알렉사 음성 제어 완벽 지원\n▶ 더 보기', '', 1600000.00, 8000),
(12931, 1, '🚲 자전거 후방 레이더 (후미등 겸용)', '', '⚡ 뒤에서 오는 차량 정보를 사이클링 컴퓨터로 확인\n💎 안전한 라이딩을 위한 필수 시인성 확보\n📌 스마트폰 앱과 연동한 알림 기능\n🚀 지금 확인', '', 990000.00, 4950),
(12932, 1, '🛴 전동 보드 (원휠 자이로스코프)', '', '✨ 몸의 무게 중심만으로 이동하는 혁신\n🎯 강력한 등판 능력과 도심 주행 최적화\n⚡ 스타일리시한 이동 수단을 찾는다면\n▶ 바로 구매', '', 380000.00, 1900),
(12933, 1, '🌡️ 비접촉식 디지털 온도계 (산업용)', '', '✨ 영하 50도부터 영상 500도까지 정밀 측정\n💎 요리, 엔진, 전기 설비 점검 시 유용\n📌 레이저 포인트로 측정 부위 확인 가능\n🚀 지금 주문', '', 1670000.00, 8350),
(12934, 1, '🧊 휴대용 무선 아이스 쿨러 20L', '', '🌬️ 배터리로 작동하는 이동식 냉장고\n✨ 야외에서도 음료와 음식을 시원하게 보관\n⚡ 캠핑 및 차박 매니아 필수 아이템\n▶ 더 보기', '', 1060000.00, 5300),
(12935, 1, '🍞 고성능 블렌더 (1500W 진공 타입)', '', '✨ 영양소 파괴를 최소화하는 진공 블렌딩\n💎 얼음도 순식간에 갈아버리는 초강력 모터\n📌 원터치 자동 세척 모드 탑재\n🚀 지금 클릭', '', 450000.00, 2250),
(12936, 1, '💧 아쿠아 구강 세정기 (휴대용)', '', '🦷 치아 사이 이물질을 강력한 수압으로 제거\n✨ 교정기 착용자 및 잇몸 관리 필수템\n⚡ 방수 지원으로 샤워 중에도 사용 가능\n▶ 확인하기', '', 1740000.00, 8700),
(12937, 1, '🧔 3헤드 회전식 전기 면도기 (건습식)', '', '✨ 굴곡진 얼굴형에도 밀착되는 유연한 헤드\n🎯 자극 없는 부드러운 절삭력\n📌 전용 세정 스테이션 포함 풀패키지\n🚀 바로 구매', '', 1130000.00, 5650),
(12938, 1, '🎵 액티브 노이즈 캔슬링 이어폰 (커널형)', '', '🎧 지하철 소음도 지워주는 강력한 소음 차단\n✨ 고음질 LDAC 코덱 지원으로 선명한 음질\n⚡ 주변 소리 듣기 모드로 안전한 보행\n▶ 구경하기', '', 520000.00, 2600),
(12939, 1, '💼 메신저 백 (방수 타포린 소재)', '', '✨ 자전거 라이딩에 최적화된 3점식 스트랩\n💎 태블릿과 노트북 수납 공간 분리\n📌 스타일과 기능성을 모두 잡은 어반 백\n🚀 지금 확인', '', 1810000.00, 9050),
(12940, 1, '💾 외장형 하드 도킹 스테이션', '', '🚀 안 쓰는 하드디스크를 외장 하드로 활용\n✨ 원터치 클론 기능으로 데이터 복제 가능\n⚡ 대용량 아카이브 관리를 위한 필수 장비\n▶ 구매하기', '', 1200000.00, 6000),
(12941, 1, '👔 휴대용 스팀 다리미 (폴더블)', '', '✨ 옷걸이에 걸린 채로 슥슥 주름 제거\n💎 강력한 스팀 분사로 살균 효과까지\n📌 여행 가방에 쏙 들어가는 접이식 핸들\n🚀 지금 주문', '', 590000.00, 2950),
(12942, 1, '🥣 가정용 진공 포장기 (밀봉형)', '', '✨ 남은 식재료를 신선하게 오래 보관하세요\n🎯 수비드 요리 준비를 위한 필수 장비\n⚡ 전용 진공 팩 롤 증정 이벤트 중\n▶ 더 보기', '', 1880000.00, 9400),
(12943, 1, '🧴 로봇 유리창 청소기 (리모컨 제어)', '', '💎 고층 아파트 외부 유리창을 깨끗하게\n✨ 강력한 흡착력과 지능형 경로 계산\n📌 손이 닿지 않는 곳까지 완벽 청소\n🚀 바로 클릭', '', 1270000.00, 6350),
(12944, 1, '🎸 전용 멀티 이펙터 (기타용)', '', '🎵 수백 가지 페달 사운드를 기기 하나로\n✨ 직관적인 LCD 화면과 풋 스위치 제어\n⚡ 공연과 녹음 시 최고의 효율성 선사\n▶ 확인하기', '', 660000.00, 3300),
(12945, 1, '🎹 롤업 건반 61키 (교육용)', '', '✨ 책상 위에 펼치면 바로 피아노가 됩니다\n🎯 내장 배터리로 야외 버스킹도 가능\n🎁 입문자를 위한 악보집 무료 증정\n🚀 지금 구매', '', 1950000.00, 9750),
(12946, 1, '🔦 충전식 LED 작업등 (마그네틱 베이스)', '', '✨ 야간 정비 및 DIY 시 밝은 시야 확보\n💎 구부러지는 헤드로 사각지대까지 비춤\n📌 보조배터리 기능으로 급속 충전 지원\n▶ 구경하기', '', 1340000.00, 6700),
(12947, 1, '🕶️ 오디오 스마트 안경 (교체용 렌즈)', '', '🎧 음악 감상과 시력 보호를 동시에\n✨ 블루라이트 차단 및 선글라스 렌즈 포함\n⚡ 가벼운 프레임으로 장시간 착용 가능\n🚀 지금 확인', '', 730000.00, 3650),
(12948, 1, '📱 차량용 헤드레스트 태블릿 거치대', '', '🎬 뒷좌석 아이들을 위한 카 시네마 완성\n✨ 흔들림 없는 고정과 간편한 장착\n📌 장거리 여행의 필수 육아 아이템\n▶ 구매하기', '', 120000.00, 600),
(12949, 1, '🧊 사각 얼음 대용량 실리콘 몰드', '', '💧 천천히 녹는 6cm 대형 얼음 제작\n✨ 위스키와 칵테일을 위한 필수 홈바 용품\n📞 냄새 배임 없는 고품질 실리콘 사용\n🚀 지금 구매', '', 1410000.00, 7050),
(12950, 1, '🦾 손 안마기 (온열 및 진동 모드)', '', '💆 컴퓨터 작업 후 지친 손목을 시원하게\n💎 공기압 지압으로 마디마디 꼼꼼한 마사지\n⚡ 화이트 톤의 깔끔한 디자인\n▶ 혜택 보기', '', 800000.00, 4000);
