INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12951, 1, '🎧 전문가용 평면 자력형 헤드폰', '', '🎵 넓은 다이내믹 레인지로 경험하는 압도적 해상도\n💎 정교한 사운드 튜닝이 필요한 믹싱 작업 최적화\n⚡ 장시간 착용에도 압박 없는 인체공학 헤드밴드\n▶ 제품 상세 보기', '', 190000.00, 950),
(12952, 1, '💻 PCIE 5.0 그래픽카드 지지대 (RGB)', '', '🚀 대형 그래픽카드의 처짐과 슬롯 파손 방지\n✨ 화려한 ARGB 효과로 내부 튜닝 완성\n🔥 강력한 자석 베이스로 간편하고 튼튼한 고정\n🚀 지금 클릭', '', 1480000.00, 7400),
(12953, 1, '⌚ 스마트워치 세라믹 링크 스트랩', '', '🎨 스크래치에 강하고 영롱한 광택의 세라믹\n💎 피부 자극 없는 매끄러운 착용감\n📌 세련된 블랙 & 화이트 프리미엄 라인업\n▶ 구경하기', '', 870000.00, 4350),
(12954, 1, '🖱️ 저소음 무선 블루투스 마우스', '', '🤫 클릭 소음 90% 감소로 공공장소 사용 최적\n✨ 슬림한 디자인으로 가방 속에 쏙!\n⚡ 한 번 충전으로 최대 3개월 사용 가능\n▶ 확인하기', '', 260000.00, 1300),
(12955, 1, '🔋 25000mAh 항공 반입 보조배터리', '', '⚡ 노트북 2회 완충 가능한 넉넉한 용량\n💎 실시간 배터리 상태 표시 LCD 디스플레이\n📌 100W PD 입출력으로 빠른 충전 속도\n🚀 바로 주문', '', 1550000.00, 7750),
(12956, 1, '📷 미러리스용 85mm 인물 전용 단렌즈', '', '🎬 찰나의 표정을 아름답게 담는 최고의 배경 흐림\n🎯 빠르고 조용한 모터로 영상 촬영에도 최적\n🎁 지금 구매 시 UV 필터 무료 증정\n▶ 상세 보기', '', 940000.00, 4700),
(12957, 1, '📺 43인치 4K 스마트 모니터 (OTT 내장)', '', '🏟️ PC 없이도 넷플릭스, 유튜브 바로 감상\n✨ 문서 작업부터 고화질 영상 시청까지 하나로\n⚡ 전용 리모컨 포함으로 편리한 조작\n🚀 지금 확인', '', 330000.00, 1650),
(12958, 1, '⌨️ 무선 기계식 키보드 (저소음 적축)', '', '💎 서걱거리는 기분 좋은 타건감과 정숙함\n✨ 사무실에서 쓰기 좋은 기계식 키보드 추천\n📌 이중 사출 키캡으로 각인 지워짐 방지\n▶ 구매하기', '', 1620000.00, 8100),
(12959, 1, '📱 스마트폰 맥세이프 쿨링 충전기', '', '✨ 충전 중 발열을 잡는 강력한 냉각 팬 탑재\n🎯 게임 중에도 프레임 드랍 없이 시원하게\n💸 무선 충전과 쿨링을 동시에 해결\n🚀 바로 구매', '', 1010000.00, 5050),
(12960, 1, '🔈 하이파이 북쉘프 스피커 (액티브)', '', '🎵 클래스 D 앰프 내장으로 깨끗한 출력\n🎨 모던한 블랙 하이그로시 디자인\n⚡ 별도 장비 없이 블루투스 연결 즉시 사용\n▶ 더 보기', '', 400000.00, 2000),
(12961, 1, '🎮 레이싱 휠 세트 (피드백 지원)', '', '🔥 실제 도로의 진동이 느껴지는 리얼 드라이빙\n🎯 정밀한 페달 조작으로 랩타임 단축\n📌 레이싱 게임 매니아를 위한 필수 장비\n🚀 지금 클릭', '', 1690000.00, 8450),
(12962, 1, '🖥️ 싱글 모니터 암 (가스 스프링 방식)', '', '✨ 자유로운 높낮이 조절로 거북목 예방\n💎 데스크 공간을 넓게 쓰는 마법 같은 정리\n⚡ 간편한 클램프 고정 방식으로 1분 설치 끝\n▶ 확인하기', '', 1080000.00, 5400),
(12963, 1, '🖨️ 영수증 프린터 (블루투스 감열식)', '', '📑 배달 앱 및 결제 시스템 완벽 연동\n💸 잉크 리필 필요 없는 간편한 유지보수\n📌 소상공인 창업 필수 지원 패키지\n🚀 지금 구매', '', 470000.00, 2350),
(12964, 1, '🧥 스마트 자세 모니터링 웨어러블', '', '✨ 등이 굽을 때마다 진동으로 알려주는 습관 교정\n🎯 전용 앱을 통해 내 자세 점수 확인 가능\n📞 거북목 고민, 이제 스마트하게 해결하세요\n▶ 제품 보기', '', 1760000.00, 8800),
(12965, 1, '🌬️ 가정용 타워형 에어 서큘레이터', '', '💎 강력한 직진성 바람으로 거실 구석까지 시원하게\n✨ 슬림한 디자인으로 공간 차지 최소화\n💸 초저전력 설계로 전기세 걱정 뚝\n🚀 지금 확인', '', 1150000.00, 5750),
(12966, 1, '🧹 차량용 고출력 무선 청소기 (블로워 겸용)', '', '🎯 흡입은 기본, 에어 블로워 기능으로 먼지 털기까지\n✨ 컴팩트한 사이즈에 숨겨진 강력한 성능\n📌 워셔블 필터로 영구적인 사용 가능\n▶ 더 보기', '', 540000.00, 2700),
(12967, 1, '🧊 차량용 미니 냉온장고 10L', '', '🎨 여름엔 시원하게, 겨울엔 따뜻하게 보관\n💎 캠핑 및 장거리 주행 시 최고의 파트너\n⚡ 차량용 시거잭 및 가정용 플러그 지원\n🚀 구매하기', '', 1830000.00, 9150),
(12968, 1, '💧 대용량 초음파 가습기 (아로마 지원)', '', '✨ 가습과 동시에 은은한 향기로 힐링하세요\n🎯 4L 대용량으로 밤새 끊김 없는 가습\n📌 무드등 기능으로 침실 분위기 업그레이드\n▶ 확인하기', '', 1220000.00, 6100),
(12969, 1, '🍳 와이드 전기 그릴 (분리형 팬)', '', '🍗 삼겹살부터 스테이크까지 한 번에 요리\n💎 전체 분리 세척 가능으로 위생적인 관리\n🎁 지금 구매 시 전용 보관 가방 증정\n🚀 지금 주문', '', 610000.00, 3050),
(12970, 1, '☕ 전자동 원두 커피 머신 (가성비 모델)', '', '☕ 갓 볶은 원두의 풍미를 집에서도 간편하게\n✨ 버튼 하나로 아메리카노 완성\n⚡ 복잡한 세척 과정 없는 자동 헹굼 기능\n▶ 구경하기', '', 1900000.00, 9500),
(12971, 1, '🏋️ 스마트 체성분 분석 체중계', '', '📈 몸무게부터 체지방률까지 12가지 지표 측정\n✨ 앱 연동으로 변화하는 내 몸을 그래프로 확인\n📌 온 가족 데이터 개별 기록 지원\n🚀 지금 구매', '', 1290000.00, 6450),
(12972, 1, '💇 전문가용 세라믹 헤어 고데기', '', '✨ 모발 손상을 줄여주는 특수 코팅 플레이트\n🎯 30초 퀵 예열로 바쁜 아침 스타일링\n⚡ 전 세계 어디서든 사용 가능한 프리볼트\n▶ 확인하기', '', 680000.00, 3400),
(12973, 1, '💆 무선 온열 눈 마사지기', '', '🔋 스마트폰과 PC 사용으로 지친 눈에 휴식을\n💎 공기압 마사지와 따뜻한 온열 찜질 효과\n📌 접이식 디자인으로 여행 시 휴대 간편\n🚀 지금 클릭', '', 1970000.00, 9850),
(12974, 1, '📽️ 4K 시네마 빔프로젝터 (안드로이드 TV)', '', '🎬 우리 집을 영화관으로 만드는 압도적 화질\n✨ 넷플릭스, 디즈니+ 등 OTT 앱 자체 실행\n🎁 전용 100인치 스크린 사은품 증정\n▶ 확인하기', '', 1360000.00, 6800),
(12975, 1, '👜 프리미엄 노트북 가죽 슬리브', '', '🎨 기기를 안전하고 우아하게 감싸는 디자인\n💎 스크래치에 강한 최고급 인조가죽 소재\n⚡ 맥북 전 라인업 맞춤 사이즈 출시\n🚀 바로 주문', '', 750000.00, 3750),
(12976, 1, '📻 올인원 블루투스 스피커 (레트로)', '', '🎵 LP 감성을 담은 클래식한 우드 바디\n✨ 라디오, USB, 블루투스 모든 연결 지원\n📌 거실 인테리어를 완성하는 소품 활용\n▶ 구경하기', '', 140000.00, 700),
(12977, 1, '📏 디지털 줄자 (레이저 거리 측정 겸용)', '', '🛠️ 실제 줄자와 레이저를 하나로 합친 혁신\n✨ 면적과 부피 자동 계산으로 작업 효율 업\n⚡ 자석 후크로 혼자서도 정밀 측정 가능\n🚀 지금 확인', '', 1430000.00, 7150),
(12978, 1, '🏮 캠핑용 LED 랜턴 (360도 조명)', '', '✨ 텐트 안을 환하게 비추는 무지향성 광원\n💎 보조배터리로 사용 가능한 대용량 탑재\n📌 IPX4 생활 방수로 야외 활동에 최적\n▶ 구매하기', '', 820000.00, 4100),
(12979, 1, '🎙️ 스트리밍 전용 콘덴서 마이크', '', '🎧 내 목소리를 더 선명하고 풍부하게\n✨ 노이즈 캔슬링 기술로 주변 소음 차단\n⚡ USB 연결로 설정 없이 바로 사용 가능\n🚀 지금 클릭', '', 210000.00, 1050),
(12980, 1, '🔌 스마트 멀티탭 (전력량 모니터링)', '', '⚡ 앱으로 밖에서도 전원을 차단해 화재 예방\n💎 가전별 전력 소비량을 실시간 확인\n📌 대기 전력 자동 차단으로 전기요금 절약\n▶ 더 보기', '', 1500000.00, 7500),
(12981, 1, '🚲 자전거용 스마트 속도계 (GPS)', '', '⚡ 라이딩 경로와 속도를 정밀하게 기록\n💎 블루투스 센서 연동으로 케이던스 측정\n📌 야간에도 잘 보이는 백라이트 디스플레이\n🚀 지금 확인', '', 890000.00, 4450),
(12982, 1, '🛴 오프로드용 전동 킥보드 (듀얼 서스펜션)', '', '✨ 비포장도로에서도 안정적인 승차감 선사\n🎯 강력한 모터 출력으로 가파른 언덕 주행\n⚡ 안전을 위한 듀얼 디스크 브레이크 탑재\n▶ 바로 구매', '', 280000.00, 1400),
(12983, 1, '🌡️ 비접촉식 디지털 적외선 온도계', '', '✨ 물체에 닿지 않고 1초 만에 온도 측정\n💎 요리 시 기름 온도나 육아 온도 체크에 필수\n📌 백라이트 LCD로 어두운 곳에서도 확인 가능\n🚀 지금 주문', '', 1570000.00, 7850),
(12984, 1, '🧊 탁상용 무선 미니 냉풍기 (수조형)', '', '🌬️ 물을 넣어 시원함을 더하는 나만의 에어컨\n✨ 저소음 설계로 공부방이나 사무실 최적\n⚡ 간편한 USB 충전식으로 이동성 극대화\n▶ 더 보기', '', 960000.00, 4800),
(12985, 1, '🍞 와플 & 샌드위치 메이커 (교체형 팬)', '', '✨ 집에서 즐기는 겉바속촉 홈브런치\n💎 붕어빵, 도넛 등 다양한 플레이트 추가 가능\n📌 논스틱 코팅으로 눌어붙지 않는 편리함\n🚀 지금 클릭', '', 350000.00, 1750),
(12986, 1, '💧 음파 전동 칫솔 (UV 살균 케이스 포함)', '', '🦷 치과에서 관리받은 듯한 강력한 세정력\n✨ 전용 케이스로 칫솔모를 항상 위생적으로\n⚡ 한 번 충전으로 한 달 사용 가능한 배터리\n▶ 확인하기', '', 1640000.00, 8200),
(12987, 1, '🧔 남성용 코털 제거기 (저소음 설계)', '', '✨ 매너 있는 남자의 필수 그루밍 아이템\n🎯 피부 손상 방지 돔형 안전 칼날 적용\n📌 흐르는 물에 바로 세척 가능한 방수 기능\n🚀 바로 구매', '', 1030000.00, 5150),
(12988, 1, '🎵 화이트 노이즈 숙면 유도기', '', '🎧 층간 소음을 덮어주는 편안한 자연의 소리\n✨ 깊은 잠을 돕는 20가지 사운드 탑재\n⚡ 타이머 설정으로 수면 후 자동 종료\n▶ 구경하기', '', 420000.00, 2100),
(12989, 1, '💼 카메라 숄더백 (쿠션 칸막이형)', '', '✨ 소중한 장비를 안전하게 보호하는 전용 백\n💎 렌즈와 바디 맞춤형 공간 조절 가능\n📌 스타일리시한 캔버스 소재로 데일리 활용\n🚀 지금 확인', '', 1710000.00, 8550),
(12990, 1, '💾 외장 SSD 2TB (방수·방진 강화)', '', '🚀 현장 작업에도 안심할 수 있는 극한의 내구성\n✨ 초당 1050MB의 압도적인 전송 속도\n⚡ 소중한 데이터를 외부 충격으로부터 보호\n▶ 구매하기', '', 1100000.00, 5500),
(12991, 1, '👔 핸디형 스팀 다리미 (퀵 스타트)', '', '✨ 예열 기다림 없이 20초 만에 바로 다림질\n💎 강력한 미세 스팀으로 주름과 냄새 제거\n📌 가벼운 무게로 출장 및 여행 시 추천\n🚀 지금 주문', '', 490000.00, 2450),
(12992, 1, '🥣 수비드 진공 포장기 (올인원 세트)', '', '✨ 육즙 가득한 수비드 요리의 완성\n🎯 원터치 자동 진공 및 밀봉 기능\n⚡ 남은 식재료 신선 보관용으로도 만점\n▶ 더 보기', '', 1780000.00, 8900),
(12993, 1, '🧴 초음파 쥬얼리 & 안경 세척기', '', '💎 틈새에 낀 오염물질을 깨끗하게 제거하세요\n✨ 물만으로도 새것 같은 반짝임 선사\n📌 소중한 액세서리 관리를 위한 필수품\n🚀 바로 클릭', '', 1170000.00, 5850),
(12994, 1, '🎸 일렉기타 입문용 풀패키지', '', '🎵 기타, 앰프, 가방, 튜너까지 모두 한 번에\n✨ 연주가 즐거워지는 최적의 세팅 완료\n⚡ 취미 생활의 시작, 합리적인 가격으로\n▶ 확인하기', '', 560000.00, 2800),
(12995, 1, '🎹 휴대용 롤업 피아노 (88건반)', '', '✨ 둘둘 말아서 가방에 쏙! 어디서든 연습 가능\n🎯 실제 피아노와 동일한 88개 건반 구성\n🎁 지금 구매 시 전용 이어폰 증정\n🚀 지금 구매', '', 1850000.00, 9250),
(12996, 1, '🔦 충전식 LED 작업등 (행잉 후크형)', '', '✨ 어두운 엔진룸이나 창고 작업 시 밝은 시야\n💎 고정 후크와 자석으로 양손 자유롭게\n📌 비상시 SOS 점멸 모드 지원\n▶ 구경하기', '', 1240000.00, 6200),
(12997, 1, '🕶️ 오디오 선글라스 (편광 렌즈)', '', '🎧 음악을 들으며 눈도 보호하는 일석이조\n✨ 오픈 이어 방식으로 안전한 야외 활동\n⚡ 등산, 낚시, 사이클링 시 최고의 파트너\n🚀 지금 확인', '', 630000.00, 3150),
(12998, 1, '📱 스마트폰 차량용 자동 거치대 (무선 충전)', '', '🎬 폰을 갖다 대면 자동으로 잡아주는 편리함\n✨ 운전 중 흔들림 없는 안정적인 고정력\n📌 고속 무선 충전 지원으로 배터리 걱정 끝\n▶ 구매하기', '', 1920000.00, 9600),
(12999, 1, '🧊 가정용 급속 제빙기 (얼음 사이즈 조절)', '', '💧 6분마다 9알의 얼음이 쏟아집니다\n✨ 캠핑장이나 홈바에서 끊임없이 즐기세요\n📞 위생적인 자동 세척 기능 탑재 모델\n🚀 상담 신청', '', 1310000.00, 6550),
(13000, 1, '🦾 무선 손 안마기 (공기압·온열)', '', '💆 고생한 내 손을 위한 매일 15분 힐링\n💎 손가락 마디마디 지압하는 섬세한 공기압\n⚡ 화이트데이, 어버이날 선물로 강력 추천\n▶ 혜택 보기', '', 700000.00, 3500);
